import type { SchoolYear } from './schoolYear';
import { ALL_SCHOOL_YEARS, DEFAULT_GRADES_ALL } from './schoolYear';
import type { NavigationItem } from './navigation';
import {
  NAVIGATION_LEAVES,
  MATHS_THEMES,
  CALCULS_SUBTHEMES,
  FRANCAIS_THEMES,
  GEOMETRIE_EXERCISES,
  SONS_EXERCISES,
  SCIENCES_EXERCISES,
  SUBJECTS,
} from './navigation';

/** Années ciblées par un item (défaut : tout le primaire). */
export function getGrades(item: NavigationItem): SchoolYear[] {
  if (item.grades?.length) return item.grades;
  return DEFAULT_GRADES_ALL;
}

/** Années pour lesquelles au moins un exercice existe (ordre CP → CM2). */
export function getAvailableSchoolYears(): SchoolYear[] {
  const set = new Set<SchoolYear>();
  for (const item of NAVIGATION_LEAVES) {
    for (const g of getGrades(item)) {
      set.add(g);
    }
  }
  return ALL_SCHOOL_YEARS.filter((y) => set.has(y));
}

export function filterCalculosSubthemesForGrade(grade: SchoolYear): NavigationItem[] {
  return CALCULS_SUBTHEMES.filter((s) => getGrades(s).includes(grade));
}

export function filterMathsThemesForGrade(grade: SchoolYear): NavigationItem[] {
  return MATHS_THEMES.filter((theme) => {
    if (theme.id === 'calculs') {
      return CALCULS_SUBTHEMES.some((s) => getGrades(s).includes(grade));
    }
    if (theme.id === 'geometrie') {
      return GEOMETRIE_EXERCISES.some((s) => getGrades(s).includes(grade));
    }
    return getGrades(theme).includes(grade);
  });
}

export function filterFrancaisThemesForGrade(grade: SchoolYear): NavigationItem[] {
  return FRANCAIS_THEMES.filter((theme) => {
    if (theme.id === 'sons') {
      return SONS_EXERCISES.some((s) => getGrades(s).includes(grade));
    }
    return getGrades(theme).includes(grade);
  });
}

export function filterGeometrieForGrade(grade: SchoolYear): NavigationItem[] {
  return GEOMETRIE_EXERCISES.filter((s) => getGrades(s).includes(grade));
}

export function filterSonsForGrade(grade: SchoolYear): NavigationItem[] {
  return SONS_EXERCISES.filter((s) => getGrades(s).includes(grade));
}

export function filterSciencesExercisesForGrade(grade: SchoolYear): NavigationItem[] {
  return SCIENCES_EXERCISES.filter((s) => getGrades(s).includes(grade));
}

export function filterSubjectsForGrade(grade: SchoolYear): NavigationItem[] {
  return SUBJECTS.filter((subject) => {
    if (subject.id === 'maths') return filterMathsThemesForGrade(grade).length > 0;
    if (subject.id === 'francais') return filterFrancaisThemesForGrade(grade).length > 0;
    if (subject.id === 'sciences') return filterSciencesExercisesForGrade(grade).length > 0;
    return getGrades(subject).includes(grade);
  });
}

/**
 * Si le chemin correspond à un exercice feuille, retourne ses années autorisées.
 * Sinon null (page de liste, accueil, etc.).
 */
export function getGradesForPathname(pathname: string): SchoolYear[] | null {
  const normalized = pathname.replace(/\/$/, '') || '/';
  const leaf = NAVIGATION_LEAVES.find((l) => l.path === normalized);
  if (!leaf) return null;
  return getGrades(leaf);
}
