/**
 * 50 mots avec leur décomposition en sons (graphèmes-phonèmes).
 * Chaque mot est tagué avec les sons remarquables qu'il contient,
 * ce qui permet le filtrage par thème de son.
 *
 * Convention : on utilise les graphèmes tels qu'ils apparaissent dans le mot.
 * Les lettres muettes finales ne sont pas comptées.
 */

export interface WordData {
  word: string;
  /** Décomposition en graphèmes-phonèmes (un élément par son entendu) */
  sounds: string[];
  /** Sons remarquables contenus dans le mot (pour le filtrage par thème) */
  themes: string[];
}

