import React from 'react';
import type { TransformationItem } from '../../../../data/transformation-problems';
import type { TransformationField } from './useTransformation';

interface TransformationBarInteractiveProps {
  item: TransformationItem;
  fields: Record<TransformationField, string>;
  activeField: TransformationField;
  onFieldChange: (f: TransformationField, v: string) => void;
  onFieldFocus: (f: TransformationField) => void;
  disabled: boolean;
}

function BarInput(props: {
  id: string;
  field: TransformationField;
  value: string;
  active: boolean;
  disabled: boolean;
  onFieldChange: (f: TransformationField, v: string) => void;
  onFieldFocus: (f: TransformationField) => void;
  ariaLabel: string;
}): React.ReactElement {
  const { id, field, value, active, disabled, onFieldChange, onFieldFocus, ariaLabel } = props;
  return (
    <input
      id={id}
      type="text"
      inputMode="numeric"
      autoComplete="off"
      className={`trans-bar-input ${active ? 'trans-bar-input-active' : ''}`}
      value={value}
      disabled={disabled}
      onChange={(e) => onFieldChange(field, e.target.value)}
      onFocus={() => onFieldFocus(field)}
      placeholder="?"
      aria-label={ariaLabel}
    />
  );
}

/**
 * Diagramme « T » partie-partie-tout : total au-dessus du trait, deux parties égales en dessous.
 */
export function TransformationBarInteractive({
  item,
  fields,
  activeField,
  onFieldChange,
  onFieldFocus,
  disabled,
}: TransformationBarInteractiveProps): React.ReactElement {
  if (item.kind === 'add') {
    return (
      <div className="trans-bar-wrap">
        <p className="trans-bar-heading">Diagramme en barres</p>
        <div className="trans-bar trans-bar-t">
          <div className="trans-bar-t-whole">
            <BarInput
              id="trans-diag-c"
              field="diag_c"
              value={fields.diag_c}
              active={activeField === 'diag_c'}
              disabled={disabled}
              onFieldChange={onFieldChange}
              onFieldFocus={onFieldFocus}
              ariaLabel="Total (tout)"
            />
          </div>
          <div className="trans-bar-t-rule" aria-hidden />
          <div className="trans-bar-t-parts">
            <div className="trans-bar-t-part">
              <BarInput
                id="trans-diag-a"
                field="diag_a"
                value={fields.diag_a}
                active={activeField === 'diag_a'}
                disabled={disabled}
                onFieldChange={onFieldChange}
                onFieldFocus={onFieldFocus}
                ariaLabel="Première partie"
              />
            </div>
            <div className="trans-bar-t-part">
              <BarInput
                id="trans-diag-b"
                field="diag_b"
                value={fields.diag_b}
                active={activeField === 'diag_b'}
                disabled={disabled}
                onFieldChange={onFieldChange}
                onFieldFocus={onFieldFocus}
                ariaLabel="Deuxième partie"
              />
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="trans-bar-wrap">
      <p className="trans-bar-heading">Diagramme en barres</p>
      <div className="trans-bar trans-bar-t">
        <div className="trans-bar-t-whole">
          <BarInput
            id="trans-diag-a"
            field="diag_a"
            value={fields.diag_a}
            active={activeField === 'diag_a'}
            disabled={disabled}
            onFieldChange={onFieldChange}
            onFieldFocus={onFieldFocus}
            ariaLabel="Nombre au départ (total)"
          />
        </div>
        <div className="trans-bar-t-rule" aria-hidden />
        <div className="trans-bar-t-parts">
          <div className="trans-bar-t-part">
            <BarInput
              id="trans-diag-b"
              field="diag_b"
              value={fields.diag_b}
              active={activeField === 'diag_b'}
              disabled={disabled}
              onFieldChange={onFieldChange}
              onFieldFocus={onFieldFocus}
              ariaLabel="Ce qu’on enlève"
            />
          </div>
          <div className="trans-bar-t-part">
            <BarInput
              id="trans-diag-c"
              field="diag_c"
              value={fields.diag_c}
              active={activeField === 'diag_c'}
              disabled={disabled}
              onFieldChange={onFieldChange}
              onFieldFocus={onFieldFocus}
              ariaLabel="Ce qui reste"
            />
          </div>
        </div>
      </div>
    </div>
  );
}
