/** Avance l’horloge 12 h de `delta` minutes (delta peut être négatif). */
export function addClock12Minutes(
  hour12: number,
  minute: number,
  delta: number
): { hour12: number; minute: number } {
  const h0 = hour12 === 12 ? 0 : hour12;
  let t = h0 * 60 + minute + delta;
  t = ((t % 720) + 720) % 720;
  const nh = Math.floor(t / 60);
  const nm = t % 60;
  const displayH = nh === 0 ? 12 : nh;
  return { hour12: displayH, minute: nm };
}

export function formatDigital12(hour12: number, minute: number): string {
  return `${hour12} h ${String(minute).padStart(2, '0')}`;
}
