import { useState, useCallback } from 'react';
import { randomInRange } from '../../../utils/randomInRange';
import { shuffleArray } from '../../../utils/shuffleArray';
import { useScore } from '../../../hooks/useScore';
import { WORDS, WordData, SoundTheme } from '../../../data/mots-sons';

interface SonState {
  /** Données du mot courant */
  wordData: WordData;
  /** Sons mélangés à placer (corrects + distracteurs) */
  availableSounds: string[];
}

interface UseSonsReturn {
  state: SonState;
  /** Sons déjà placés par l'enfant dans les cases */
  placedSounds: string[];
  isCorrect: boolean | null;
  /** Place le prochain son dans la première case vide */
  placeSound: (sound: string) => void;
  /** Retire le dernier son placé */
  removeLast: () => void;
  next: () => void;
  themeFilter: SoundTheme | null;
  setThemeFilter: (theme: SoundTheme | null) => void;
}

/** Génère quelques sons distracteurs qui ne sont pas dans le mot */
function generateDistractors(correctSounds: string[]): string[] {
  const allSounds = ['a', 'e', 'i', 'o', 'u', 'ou', 'on', 'an', 'in', 'ch', 'ai', 'eau', 'oi', 'r', 'l', 's', 't', 'p', 'b', 'd', 'f', 'g', 'n', 'm', 'v', 'j'];
  const distractors = allSounds.filter((s) => !correctSounds.includes(s));
  return shuffleArray(distractors).slice(0, Math.min(3, distractors.length));
}

/** Génère une question : un mot avec ses sons mélangés + distracteurs */
function generateSonQuestion(themeFilter: SoundTheme | null): SonState {
  let pool = WORDS;
  if (themeFilter) {
    pool = WORDS.filter((w) => w.themes.includes(themeFilter));
  }
  /* Fallback si le filtre ne donne rien */
  if (pool.length === 0) pool = WORDS;

  const wordData = pool[randomInRange(0, pool.length - 1)];
  const distractors = generateDistractors(wordData.sounds);
  const availableSounds = shuffleArray([...wordData.sounds, ...distractors]);

  return { wordData, availableSounds };
}

/**
 * Hook pour l'exercice de découpe en sons.
 * Gère le placement des sons dans les cases et la validation.
 */
export function useSons(): UseSonsReturn {
  const { addPoint, removePoint } = useScore();
  const [themeFilter, setThemeFilter] = useState<SoundTheme | null>(null);
  const [state, setState] = useState(() => generateSonQuestion(null));
  const [placedSounds, setPlacedSounds] = useState<string[]>([]);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);

  /** Place un son dans la prochaine case vide */
  const placeSound = useCallback(
    (sound: string) => {
      if (isCorrect !== null) return;
      const newPlaced = [...placedSounds, sound];
      setPlacedSounds(newPlaced);

      /* Vérifie automatiquement quand toutes les cases sont remplies */
      if (newPlaced.length === state.wordData.sounds.length) {
        const correct = newPlaced.every((s, i) => s === state.wordData.sounds[i]);
        setIsCorrect(correct);
        if (correct) addPoint();
        else removePoint();
      }
    },
    [placedSounds, state.wordData.sounds, isCorrect, addPoint, removePoint]
  );

  /** Retire le dernier son placé */
  const removeLast = useCallback(() => {
    if (isCorrect !== null || placedSounds.length === 0) return;
    setPlacedSounds((prev) => prev.slice(0, -1));
  }, [isCorrect, placedSounds.length]);

  const next = useCallback(() => {
    setState(generateSonQuestion(themeFilter));
    setPlacedSounds([]);
    setIsCorrect(null);
  }, [themeFilter]);

  /** Change le filtre de thème et génère une nouvelle question */
  const handleSetThemeFilter = useCallback((theme: SoundTheme | null) => {
    setThemeFilter(theme);
    setState(generateSonQuestion(theme));
    setPlacedSounds([]);
    setIsCorrect(null);
  }, []);

  return {
    state, placedSounds, isCorrect, placeSound, removeLast,
    next, themeFilter, setThemeFilter: handleSetThemeFilter,
  };
}
