import React from 'react';
import { Link } from 'react-router-dom';
import { NavigationItem } from '../data/navigation';

interface ThemeCardProps {
  item: NavigationItem;
}

/**
 * Carte cliquable pour naviguer vers un thème, sous-thème ou exercice.
 */
export function ThemeCard({ item }: ThemeCardProps): React.ReactElement {
  return (
    <Link to={item.path} className="theme-card">
      {item.icon && <span className="theme-card-icon">{item.icon}</span>}
      <div>
        <div className="theme-card-label">{item.label}</div>
        {item.description && <div className="theme-card-desc">{item.description}</div>}
      </div>
    </Link>
  );
}
