import React from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { Feedback } from '../../../components/Feedback';
import { useExerciseAnswerLimit } from '../../../hooks/useExerciseAnswerLimit';
import { useTrouveSon } from './useTrouveSon';
import { SOUND_THEMES } from '../../../data/mots-sons';

/**
 * Exercice "Trouve le son" : un mot est affiché avec autant de cases que de sons.
 * L'enfant doit cliquer sur la/les case(s) où il entend le son demandé.
 * Ex: "maison" [m, ai, s, on] → cliquer sur la 4e case pour le son "on".
 */
export function TrouveSon(): React.ReactElement {
  const {
    state, selectedIndices, toggleIndex, check, isCorrect,
    next, themeFilter, setThemeFilter,
  } = useTrouveSon();
  const { wrapNext } = useExerciseAnswerLimit('/francais/sons');

  return (
    <ExerciseWrapper title="Trouve le son" backPath="/francais/sons">
      {/* Filtre par thème de son */}
      <div className="theme-filter">
        <button
          className={`theme-filter-btn ${themeFilter === null ? 'theme-filter-btn-active' : ''}`}
          onClick={() => setThemeFilter(null)}
        >
          Tous
        </button>
        {SOUND_THEMES.map((theme) => (
          <button
            key={theme}
            className={`theme-filter-btn ${themeFilter === theme ? 'theme-filter-btn-active' : ''}`}
            onClick={() => setThemeFilter(theme)}
          >
            {theme}
          </button>
        ))}
      </div>

      {/* Consigne */}
      <div style={{ fontSize: 20, textAlign: 'center' }}>
        Où entends-tu le son <strong style={{ color: '#2ECC71' }}>"{state.targetSound}"</strong> ?
      </div>

      {/* Mot affiché */}
      <div className="sound-boxes-word">{state.word.word}</div>

      {/* Cases cliquables (une par son) */}
      <div className="sound-boxes-row">
        {state.word.sounds.map((_, i) => {
          const isSelected = selectedIndices.has(i);
          /* Après validation : vert si correct, rouge si mauvais choix */
          let extraStyle: React.CSSProperties = {};
          if (isCorrect !== null) {
            if (state.correctIndices.includes(i)) {
              extraStyle = { borderColor: '#27AE60', background: '#E8F5E9' };
            } else if (isSelected) {
              extraStyle = { borderColor: '#E74C3C', background: '#FFEBEE' };
            }
          }

          return (
            <div
              key={i}
              className={`sound-box ${isSelected ? 'sound-box-filled' : ''}`}
              style={{ minWidth: 55, minHeight: 55, fontSize: 20, ...extraStyle }}
              onClick={() => toggleIndex(i)}
            >
              {/* Numéro de la case pour aider l'enfant */}
              {i + 1}
            </div>
          );
        })}
      </div>

      {/* Bouton vérifier ou feedback */}
      {isCorrect === null ? (
        <button
          className="feedback-next"
          onClick={check}
          disabled={selectedIndices.size === 0}
        >
          Vérifier
        </button>
      ) : (
        <Feedback
          isCorrect={isCorrect}
          detail={`${state.word.word} → ${state.word.sounds.join(' · ')}`}
          onNext={() => wrapNext(next)}
        />
      )}
    </ExerciseWrapper>
  );
}
