/**
 * Années scolaire du cycle primaire (ordre d'affichage du sélecteur).
 */
export type SchoolYear = 'CP' | 'CE1' | 'CE2' | 'CM1' | 'CM2';

export const ALL_SCHOOL_YEARS: SchoolYear[] = ['CP', 'CE1', 'CE2', 'CM1', 'CM2'];

/** Clé localStorage pour la classe choisie */
export const SCHOOL_YEAR_STORAGE_KEY = 'edmond-school-year';

/** Toutes les classes pour lesquelles un exercice est proposé par défaut (tout le primaire). */
export const DEFAULT_GRADES_ALL: SchoolYear[] = [...ALL_SCHOOL_YEARS];

export function isSchoolYear(value: string): value is SchoolYear {
  return (ALL_SCHOOL_YEARS as string[]).includes(value);
}
