import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import {
  TROUVE_ARTICLE_MOTS,
  type TrouveArticleDeterminant,
  type TrouveArticleMot,
} from '../../../data/trouve-article-mots';

const DETERMINANT_CHOICES: TrouveArticleDeterminant[] = ['le', 'la', "l'", 'un', 'une'];

/** Taille d’une partie en mode « une question à la fois ». */
const STEP_SESSION_SIZE = 12;

function shuffleArticleMots(mots: TrouveArticleMot[]): TrouveArticleMot[] {
  const a = [...mots];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function formatNounWithArticle(m: TrouveArticleMot): string {
  return m.article === "l'" ? `${m.article}${m.noun}` : `${m.article} ${m.noun}`;
}

function parseDeterminantInput(raw: string): TrouveArticleDeterminant | null {
  const t = raw
    .trim()
    .toLowerCase()
    .replace(/[''`´’]/g, "'");
  if (t === 'le') return 'le';
  if (t === 'la') return 'la';
  if (t === "l'" || t === 'l') return "l'";
  if (t === 'un') return 'un';
  if (t === 'une') return 'une';
  return null;
}

function ArticleCellEntourer({
  mot,
  selected,
  disabled,
  showCorrection,
  onPick,
}: {
  mot: TrouveArticleMot;
  selected: TrouveArticleDeterminant | null;
  disabled: boolean;
  showCorrection: boolean;
  onPick: (id: number, a: TrouveArticleDeterminant) => void;
}): React.ReactElement {
  const ok = showCorrection && selected === mot.article;
  const bad = showCorrection && !ok;

  return (
    <div
      className={`article-cell${bad ? ' article-cell-wrong' : ''}${ok ? ' article-cell-ok' : ''}`}
    >
      <div className="article-cell-illus" aria-hidden>
        {mot.emoji}
      </div>
      <div className="article-cell-pick">
        <div className="article-cell-articles" role="group" aria-label={`Déterminants pour « ${mot.noun} »`}>
          {DETERMINANT_CHOICES.map((a) => {
            const isSel = selected === a;
            const label = a === "l'" ? "l'" : a;
            return (
              <button
                key={a}
                type="button"
                className={`article-choice ${isSel ? 'article-choice-selected' : ''}`}
                disabled={disabled}
                onClick={() => onPick(mot.id, a)}
              >
                {label}
              </button>
            );
          })}
        </div>
        <div className="article-cell-noun">
          {mot.noun}
          {bad ? (
            <span className="article-cell-answer">
              {' '}
              →{' '}
              {mot.article === "l'"
                ? `${mot.article}${mot.noun}`
                : `${mot.article} ${mot.noun}`}
            </span>
          ) : null}
        </div>
      </div>
    </div>
  );
}

function ArticleCellEcrire({
  mot,
  value,
  disabled,
  showCorrection,
  onChange,
}: {
  mot: TrouveArticleMot;
  value: string;
  disabled: boolean;
  showCorrection: boolean;
  onChange: (id: number, text: string) => void;
}): React.ReactElement {
  const parsed = parseDeterminantInput(value);
  const ok = showCorrection && parsed === mot.article;
  const bad = showCorrection && !ok;

  return (
    <div
      className={`article-cell${bad ? ' article-cell-wrong' : ''}${ok ? ' article-cell-ok' : ''}`}
    >
      <div className="article-cell-illus" aria-hidden>
        {mot.emoji}
      </div>
      <div className="article-cell-pick article-cell-pick--write">
        <input
          type="text"
          className="article-cell-write-input"
          value={value}
          onChange={(e) => onChange(mot.id, e.target.value)}
          disabled={disabled}
          aria-label={`Écris le déterminant devant « ${mot.noun} »`}
          autoCapitalize="off"
          autoCorrect="off"
          spellCheck={false}
          inputMode="text"
          maxLength={5}
        />
        <div className="article-cell-noun article-cell-noun--write">
          {mot.noun}
          {bad ? (
            <span className="article-cell-answer">
              {' '}
              →{' '}
              {mot.article === "l'"
                ? `${mot.article}${mot.noun}`
                : `${mot.article} ${mot.noun}`}
            </span>
          ) : null}
        </div>
      </div>
    </div>
  );
}

export type ArticleWorksheetGridVariant = 'auto-fill' | 'three-cols';

/** Saisie au clavier (fiche manuscrite) vs choix en tapant (entourer à l’écran). */
export type ArticleWorksheetMode = 'ecrire' | 'entourer';

export type ArticleWorksheetLayout = 'grid' | 'stepper';

export interface ArticleWorksheetProps {
  /** Nombre affiché dans le carré bleu (ex. 1 sur la fiche) */
  badge?: string;
  exerciseTitle: string;
  /** Grille type manuel : 3 colonnes sur écran large */
  gridVariant?: ArticleWorksheetGridVariant;
  mode?: ArticleWorksheetMode;
  /** `stepper` : une question à la fois (défaut). `grid` : feuille complète. */
  layout?: ArticleWorksheetLayout;
}

const INSTRUCTION_ENTOURER = (
  <>
    Entoure le déterminant qui convient devant chaque nom : <strong>le</strong>, <strong>la</strong>,{' '}
    <strong>l&apos;</strong>, <strong>un</strong> ou <strong>une</strong>.
  </>
);

const INSTRUCTION_ECRIRE = (
  <>
    Devant chaque nom, écris le déterminant qui convient : <strong>le</strong>, <strong>la</strong>,{' '}
    <strong>l&apos;</strong>, <strong>un</strong> ou <strong>une</strong>.
  </>
);

const INSTRUCTION_STEPPER_ECRIRE = (
  <>
    Écris le déterminant qui convient : <strong>le</strong>, <strong>la</strong>, <strong>l&apos;</strong>,{' '}
    <strong>un</strong> ou <strong>une</strong>. Une question à la fois.
  </>
);

const INSTRUCTION_STEPPER_ENTOURER = (
  <>
    Choisis le déterminant qui convient : <strong>le</strong>, <strong>la</strong>, <strong>l&apos;</strong>,{' '}
    <strong>un</strong> ou <strong>une</strong>. Une question à la fois.
  </>
);

function ArticleEcrireStepper({ badge }: { badge: string }): React.ReactElement {
  const [sessionKey, setSessionKey] = useState(0);
  const session = useMemo(
    () => shuffleArticleMots(TROUVE_ARTICLE_MOTS).slice(0, STEP_SESSION_SIZE),
    [sessionKey]
  );
  const [index, setIndex] = useState(0);
  const [draft, setDraft] = useState('');
  const [feedback, setFeedback] = useState<'idle' | 'ok' | 'wrong'>('idle');
  const [correctCount, setCorrectCount] = useState(0);
  const [roundDone, setRoundDone] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const mot = session[index] ?? null;
  const total = session.length;

  useEffect(() => {
    if (!roundDone && feedback === 'idle') {
      inputRef.current?.focus();
    }
  }, [index, sessionKey, roundDone, feedback]);

  const restartSession = useCallback(() => {
    setSessionKey((k) => k + 1);
    setIndex(0);
    setDraft('');
    setFeedback('idle');
    setCorrectCount(0);
    setRoundDone(false);
  }, []);

  const handleVerify = useCallback(() => {
    if (!mot || feedback !== 'idle') return;
    const parsed = parseDeterminantInput(draft);
    if (parsed === mot.article) {
      setCorrectCount((c) => c + 1);
      setFeedback('ok');
    } else {
      setFeedback('wrong');
    }
  }, [mot, draft, feedback]);

  const handleNext = useCallback(() => {
    if (index >= total - 1) {
      setRoundDone(true);
      setFeedback('idle');
      return;
    }
    setIndex((i) => i + 1);
    setDraft('');
    setFeedback('idle');
  }, [index, total]);

  const rowClass =
    feedback === 'ok' ? ' article-stepper-row-ok' : feedback === 'wrong' ? ' article-stepper-row-wrong' : '';

  return (
    <div className="article-stepper">
      <header className="article-stepper-head">
        <span className="article-stepper-badge" aria-hidden>
          {badge}
        </span>
        <p className="article-stepper-instruction">{INSTRUCTION_STEPPER_ECRIRE}</p>
      </header>

      {roundDone ? (
        <>
          <p className="article-stepper-summary" role="status">
            Tu as <strong>{correctCount}</strong> bonne{correctCount !== 1 ? 's' : ''} réponse
            {correctCount !== 1 ? 's' : ''} sur {total}.
          </p>
          <footer className="article-stepper-footer">
            <div className="article-stepper-actions">
              <button type="button" className="article-btn article-btn-primary" onClick={restartSession}>
                Recommencer
              </button>
            </div>
          </footer>
        </>
      ) : null}

      {!roundDone && mot ? (
        <>
          <p className="article-stepper-progress" aria-live="polite">
            Question {index + 1} / {total}
          </p>
          <div className="article-stepper-progress-bar" aria-hidden>
            <div className="article-stepper-progress-fill" style={{ width: `${((index + 1) / total) * 100}%` }} />
          </div>

          <div className={`article-stepper-card${rowClass}`}>
            <div className="article-stepper-emoji" aria-hidden>
              {mot.emoji}
            </div>
            <p className="article-stepper-prompt">
              <span className="article-stepper-prompt-label">Quel déterminant devant</span>{' '}
              <span className="article-stepper-noun">{mot.noun}</span> ?
            </p>
            <div className="article-stepper-answer-row">
              <input
                ref={inputRef}
                type="text"
                className="article-stepper-input"
                value={draft}
                onChange={(e) => setDraft(e.target.value)}
                disabled={feedback !== 'idle'}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && feedback === 'idle' && draft.trim() !== '') {
                    e.preventDefault();
                    handleVerify();
                  }
                }}
                aria-label={`Déterminant devant « ${mot.noun} » : le, la, l', un ou une`}
                autoCapitalize="off"
                autoCorrect="off"
                spellCheck={false}
                inputMode="text"
                maxLength={5}
                placeholder="le, une…"
              />
            </div>
            {feedback === 'wrong' ? (
              <p className="article-stepper-reveal" role="status">
                La bonne réponse : <strong>{formatNounWithArticle(mot)}</strong>
              </p>
            ) : null}
          </div>

          <footer className="article-stepper-footer">
            {feedback === 'ok' ? (
              <p className="article-stepper-success" role="status">
                Bravo !
              </p>
            ) : null}
            <div className="article-stepper-actions">
              {feedback === 'idle' ? (
                <button
                  type="button"
                  className="article-btn article-btn-primary"
                  onClick={handleVerify}
                  disabled={draft.trim() === ''}
                >
                  Vérifier
                </button>
              ) : (
                <button type="button" className="article-btn article-btn-primary" onClick={handleNext}>
                  {index >= total - 1 ? 'Voir le résultat' : 'Question suivante'}
                </button>
              )}
              <button type="button" className="article-btn" onClick={restartSession}>
                Nouvelle série
              </button>
            </div>
          </footer>
        </>
      ) : null}
    </div>
  );
}

function ArticleEntourerStepper({ badge }: { badge: string }): React.ReactElement {
  const [sessionKey, setSessionKey] = useState(0);
  const session = useMemo(
    () => shuffleArticleMots(TROUVE_ARTICLE_MOTS).slice(0, STEP_SESSION_SIZE),
    [sessionKey]
  );
  const [index, setIndex] = useState(0);
  const [feedback, setFeedback] = useState<'idle' | 'ok' | 'wrong'>('idle');
  const [correctCount, setCorrectCount] = useState(0);
  const [roundDone, setRoundDone] = useState(false);

  const mot = session[index] ?? null;
  const total = session.length;

  const restartSession = useCallback(() => {
    setSessionKey((k) => k + 1);
    setIndex(0);
    setFeedback('idle');
    setCorrectCount(0);
    setRoundDone(false);
  }, []);

  const handlePick = useCallback(
    (a: TrouveArticleDeterminant) => {
      if (!mot || roundDone || feedback === 'ok') return;
      if (a === mot.article) {
        setCorrectCount((c) => c + 1);
        setFeedback('ok');
      } else {
        setFeedback('wrong');
      }
    },
    [mot, roundDone, feedback]
  );

  const handleNext = useCallback(() => {
    if (index >= total - 1) {
      setRoundDone(true);
      setFeedback('idle');
      return;
    }
    setIndex((i) => i + 1);
    setFeedback('idle');
  }, [index, total]);

  const rowClass =
    feedback === 'ok' ? ' article-stepper-row-ok' : feedback === 'wrong' ? ' article-stepper-row-wrong' : '';

  return (
    <div className="article-stepper">
      <header className="article-stepper-head">
        <span className="article-stepper-badge" aria-hidden>
          {badge}
        </span>
        <p className="article-stepper-instruction">{INSTRUCTION_STEPPER_ENTOURER}</p>
      </header>

      {roundDone ? (
        <>
          <p className="article-stepper-summary" role="status">
            Tu as <strong>{correctCount}</strong> bonne{correctCount !== 1 ? 's' : ''} réponse
            {correctCount !== 1 ? 's' : ''} sur {total}.
          </p>
          <footer className="article-stepper-footer">
            <div className="article-stepper-actions">
              <button type="button" className="article-btn article-btn-primary" onClick={restartSession}>
                Recommencer
              </button>
            </div>
          </footer>
        </>
      ) : null}

      {!roundDone && mot ? (
        <>
          <p className="article-stepper-progress" aria-live="polite">
            Question {index + 1} / {total}
          </p>
          <div className="article-stepper-progress-bar" aria-hidden>
            <div className="article-stepper-progress-fill" style={{ width: `${((index + 1) / total) * 100}%` }} />
          </div>

          <div className={`article-stepper-card${rowClass}`}>
            <div className="article-stepper-emoji" aria-hidden>
              {mot.emoji}
            </div>
            <p className="article-stepper-prompt">
              <span className="article-stepper-prompt-label">Quel déterminant devant</span>{' '}
              <span className="article-stepper-noun">{mot.noun}</span> ?
            </p>
            <div className="article-stepper-choices" role="group" aria-label="Cinq déterminants au choix">
              {DETERMINANT_CHOICES.map((a) => {
                const label = a === "l'" ? "l'" : a;
                const isCorrect = feedback === 'ok' && a === mot.article;
                const disabled = feedback === 'ok' && a !== mot.article;
                return (
                  <button
                    key={a}
                    type="button"
                    className={`article-stepper-choice${isCorrect ? ' article-stepper-choice-correct' : ''}`}
                    onClick={() => handlePick(a)}
                    disabled={disabled}
                    aria-pressed={isCorrect}
                  >
                    {label}
                  </button>
                );
              })}
            </div>
          </div>

          <footer className="article-stepper-footer">
            {feedback === 'ok' ? (
              <p className="article-stepper-success" role="status">
                Bravo !
              </p>
            ) : null}
            {feedback === 'wrong' ? (
              <p className="article-stepper-hint" role="alert">
                Ce n&apos;est pas le bon déterminant. Essaie encore !
              </p>
            ) : null}
            <div className="article-stepper-actions">
              {feedback === 'ok' ? (
                <button type="button" className="article-btn article-btn-primary" onClick={handleNext}>
                  {index >= total - 1 ? 'Voir le résultat' : 'Question suivante'}
                </button>
              ) : null}
              <button type="button" className="article-btn" onClick={restartSession}>
                Nouvelle série
              </button>
            </div>
          </footer>
        </>
      ) : null}
    </div>
  );
}

function ArticleWorksheetGrid({
  badge,
  exerciseTitle,
  gridVariant,
  mode,
}: {
  badge: string;
  exerciseTitle: string;
  gridVariant: ArticleWorksheetGridVariant;
  mode: ArticleWorksheetMode;
}): React.ReactElement {
  const [selections, setSelections] = useState<Record<number, TrouveArticleDeterminant | null>>({});
  const [writings, setWritings] = useState<Record<number, string>>({});
  const [phase, setPhase] = useState<'editing' | 'corrected'>('editing');

  const onPick = useCallback(
    (id: number, a: TrouveArticleDeterminant) => {
      if (phase === 'corrected') return;
      setSelections((prev) => ({ ...prev, [id]: a }));
    },
    [phase]
  );

  const onWrite = useCallback(
    (id: number, text: string) => {
      if (phase === 'corrected') return;
      setWritings((prev) => ({ ...prev, [id]: text }));
    },
    [phase]
  );

  const stats = useMemo(() => {
    let filled = 0;
    let correct = 0;
    for (const m of TROUVE_ARTICLE_MOTS) {
      if (mode === 'ecrire') {
        const raw = writings[m.id] ?? '';
        if (raw.trim() !== '') {
          filled += 1;
          if (parseDeterminantInput(raw) === m.article) correct += 1;
        }
      } else {
        const s = selections[m.id];
        if (s !== null && s !== undefined) {
          filled += 1;
          if (s === m.article) correct += 1;
        }
      }
    }
    return { filled, correct, total: TROUVE_ARTICLE_MOTS.length };
  }, [mode, selections, writings]);

  const handleVerifyAll = useCallback(() => {
    setPhase('corrected');
  }, []);

  const handleReset = useCallback(() => {
    setSelections({});
    setWritings({});
    setPhase('editing');
  }, []);

  const showCorrection = phase === 'corrected';
  const gridClass =
    gridVariant === 'three-cols' ? 'article-grid article-grid--three' : 'article-grid';

  return (
    <ExerciseWrapper title={exerciseTitle} backPath="/francais">
      <div className="article-worksheet">
        <header className="article-worksheet-header">
          <span className="article-worksheet-badge" aria-hidden>
            {badge}
          </span>
          <p className="article-worksheet-instruction">
            {mode === 'ecrire' ? INSTRUCTION_ECRIRE : INSTRUCTION_ENTOURER}
          </p>
        </header>

        <div className={gridClass}>
          {TROUVE_ARTICLE_MOTS.map((mot) =>
            mode === 'ecrire' ? (
              <ArticleCellEcrire
                key={mot.id}
                mot={mot}
                value={writings[mot.id] ?? ''}
                disabled={showCorrection}
                showCorrection={showCorrection}
                onChange={onWrite}
              />
            ) : (
              <ArticleCellEntourer
                key={mot.id}
                mot={mot}
                selected={selections[mot.id] ?? null}
                disabled={showCorrection}
                showCorrection={showCorrection}
                onPick={onPick}
              />
            )
          )}
        </div>

        <footer className="article-worksheet-footer">
          {showCorrection ? (
            <>
              <p className="article-summary" role="status">
                Résultat : {stats.correct} bonne{stats.correct !== 1 ? 's' : ''} réponse
                {stats.correct !== 1 ? 's' : ''} sur {stats.total}.
              </p>
              <button type="button" className="article-btn article-btn-primary" onClick={handleReset}>
                Recommencer
              </button>
            </>
          ) : (
            <>
              <p className="article-progress">
                {stats.filled} / {stats.total} mots complétés
              </p>
              <button type="button" className="article-btn article-btn-primary" onClick={handleVerifyAll}>
                Vérifier
              </button>
            </>
          )}
        </footer>
      </div>
    </ExerciseWrapper>
  );
}

/**
 * Feuille commune : déterminants le / la / l’ / un / une (100 mots).
 * Par défaut : une question à la fois (`stepper`) pour les deux modes.
 */
export function ArticleWorksheet({
  badge = '1',
  exerciseTitle,
  gridVariant = 'auto-fill',
  mode = 'entourer',
  layout: layoutProp,
}: ArticleWorksheetProps): React.ReactElement {
  const layout = layoutProp ?? 'stepper';

  if (layout === 'stepper') {
    if (mode === 'ecrire') {
      return (
        <ExerciseWrapper title={exerciseTitle} backPath="/francais">
          <ArticleEcrireStepper badge={badge} />
        </ExerciseWrapper>
      );
    }
    return (
      <ExerciseWrapper title={exerciseTitle} backPath="/francais">
        <ArticleEntourerStepper badge={badge} />
      </ExerciseWrapper>
    );
  }

  return (
    <ArticleWorksheetGrid
      badge={badge}
      exerciseTitle={exerciseTitle}
      gridVariant={gridVariant}
      mode={mode}
    />
  );
}
