import React, { useState } from 'react';
import { Link, Outlet } from 'react-router-dom';
import { ScoreDisplay } from './ScoreDisplay';
import { OptionsMenu } from './OptionsMenu';

/**
 * Layout principal avec header et zone de contenu.
 * Utilisé pour les pages de navigation (accueil, listes de thèmes).
 * Les exercices utilisent ExerciseWrapper à la place.
 */
export function Layout(): React.ReactElement {
  const [optionsOpen, setOptionsOpen] = useState(false);

  return (
    <>
      <header className="layout-header">
        <Link to="/" className="layout-header-brand" title="Accueil Edmond">
          Edmond
        </Link>
        <span className="layout-header-tagline">Exercices éducatifs CP</span>
        <div className="layout-header-actions">
          <button
            type="button"
            className="options-menu-trigger options-menu-trigger--layout"
            onClick={() => setOptionsOpen(true)}
            aria-label="Ouvrir les options"
          >
            ⚙️
          </button>
          <span className="layout-header-score" aria-label="Score">
            <ScoreDisplay />
          </span>
        </div>
      </header>
      <OptionsMenu
        variant="layout"
        open={optionsOpen}
        onOpenChange={setOptionsOpen}
      />
      <main className="layout-content">
        <Outlet />
      </main>
    </>
  );
}
