import { DEVINETTE_MOTS_BANK } from './devinettes-mots-composes';

/** Paire pour mots composés avec tiret (exercice « Compose les mots »). */
export interface ComposeMotPair {
  left: string;
  right: string;
  compound: string;
}

/** Exemples du manuel (conservés en tête de liste). */
const COMPOSE_MOTS_PAIRS_BASE: ComposeMotPair[] = [
  { left: 'pique', right: 'nique', compound: 'pique-nique' },
  { left: 'grand', right: 'mère', compound: 'grand-mère' },
  { left: 'cerf', right: 'volant', compound: 'cerf-volant' },
  { left: 'grille', right: 'pain', compound: 'grille-pain' },
  { left: 'ping', right: 'pong', compound: 'ping-pong' },
  { left: 'coupe', right: 'ongles', compound: 'coupe-ongles' },
];

function stripLeadingArticle(phrase: string): string {
  let s = phrase.trim().normalize('NFC').replace(/\u2019/g, "'");
  const lower = s.toLowerCase();
  if (lower.startsWith("l'")) return s.slice(2).trim();
  if (lower.startsWith('le ')) return s.slice(3).trim();
  if (lower.startsWith('la ')) return s.slice(3).trim();
  if (lower.startsWith('les ')) return s.slice(4).trim();
  if (lower.startsWith('un ')) return s.slice(3).trim();
  if (lower.startsWith('une ')) return s.slice(4).trim();
  if (lower.startsWith('des ')) return s.slice(4).trim();
  return s;
}

/**
 * Mots composés (avec tiret) issus de la banque des devinettes.
 * Chaque mot de droite n’apparaît qu’une fois (contrainte de l’exercice).
 */
function pairsFromDevinetteBank(bank: string[]): ComposeMotPair[] {
  const seenCompound = new Set<string>();
  const seenRight = new Set<string>();

  for (const p of COMPOSE_MOTS_PAIRS_BASE) {
    seenCompound.add(p.compound.toLowerCase());
    seenRight.add(p.right.toLowerCase());
  }

  const out: ComposeMotPair[] = [];
  for (const answer of bank) {
    const core = stripLeadingArticle(answer);
    if (!core.includes('-')) continue;

    const idx = core.indexOf('-');
    const left = core.slice(0, idx).trim();
    const right = core.slice(idx + 1).trim();
    if (!left || !right) continue;

    const ck = core.toLowerCase();
    const rk = right.toLowerCase();
    if (seenCompound.has(ck) || seenRight.has(rk)) continue;

    seenCompound.add(ck);
    seenRight.add(rk);
    out.push({ left, right, compound: core });
  }

  return out;
}

/** Jeu du manuel + mots composés de la banque des devinettes. */
export const COMPOSE_MOTS_PAIRS: ComposeMotPair[] = [
  ...COMPOSE_MOTS_PAIRS_BASE,
  ...pairsFromDevinetteBank(DEVINETTE_MOTS_BANK),
];
