import React from 'react';
import { Link } from 'react-router-dom';
import { NavigationItem } from '../data/navigation';
import { ThemeCard } from './ThemeCard';

interface SubjectListProps {
  /** Titre affiché au-dessus de la liste */
  title: string;
  /** Éléments de navigation à afficher en cartes */
  items: NavigationItem[];
  /** Chemin de retour (affiche une flèche si fourni) */
  backPath?: string;
}

/**
 * Liste générique de cartes de navigation.
 * Utilisée par toutes les pages de listing (Home, MathsHome, etc.).
 * Affiche une flèche de retour quand backPath est fourni.
 */
export function SubjectList({ title, items, backPath }: SubjectListProps): React.ReactElement {
  return (
    <div>
      {backPath && (
        <Link to={backPath} className="back-link" style={{ marginBottom: '1rem' }}>
          ← Retour
        </Link>
      )}
      <h2 className="home-title">{title}</h2>
      {items.length === 0 ? (
        <p className="home-empty">
          Aucun exercice pour ta classe ici. Choisis une autre année dans le menu <strong>Options</strong>{' '}
          (icône ⚙️ en haut à droite), ou reviens plus tard.
        </p>
      ) : (
        <div className="card-grid">
          {items.map((item) => (
            <ThemeCard key={item.id} item={item} />
          ))}
        </div>
      )}
    </div>
  );
}
