import React from 'react';

interface RangeSelectorProps {
  range: { min: number; max: number };
  onChange: (range: { min: number; max: number }) => void;
}

/**
 * Sélecteur de plage de nombres (min / max).
 * Compact, affiché en haut des exercices de maths pour ajuster la difficulté.
 * Flèches haut / bas pour modifier chaque valeur sans passer par le clavier numérique.
 */
export function RangeSelector({ range, onChange }: RangeSelectorProps): React.ReactElement {
  const stepMin = (delta: number): void => {
    const next = range.min + delta;
    if (next >= 0 && next < range.max) onChange({ ...range, min: next });
  };

  const stepMax = (delta: number): void => {
    const next = range.max + delta;
    if (next > range.min) onChange({ ...range, max: next });
  };

  /** Met à jour min en s'assurant qu'il reste inférieur à max */
  const handleMinChange = (e: React.ChangeEvent<HTMLInputElement>): void => {
    const value = parseInt(e.target.value, 10);
    if (!isNaN(value) && value < range.max) {
      onChange({ ...range, min: Math.max(0, value) });
    }
  };

  /** Met à jour max en s'assurant qu'il reste supérieur à min */
  const handleMaxChange = (e: React.ChangeEvent<HTMLInputElement>): void => {
    const value = parseInt(e.target.value, 10);
    if (!isNaN(value) && value > range.min) {
      onChange({ ...range, max: value });
    }
  };

  return (
    <div className="range-selector">
      <span>De</span>
      <div className="range-selector-spin-wrap">
        <div className="range-selector-spin">
          <button
            type="button"
            className="range-selector-step"
            onClick={() => stepMin(1)}
            disabled={range.min >= range.max - 1}
            aria-label="Augmenter le plus petit nombre"
          >
            ▲
          </button>
          <button
            type="button"
            className="range-selector-step"
            onClick={() => stepMin(-1)}
            disabled={range.min <= 0}
            aria-label="Diminuer le plus petit nombre"
          >
            ▼
          </button>
        </div>
        <input type="number" value={range.min} onChange={handleMinChange} aria-label="Plus petit nombre de la plage" />
      </div>
      <span>à</span>
      <div className="range-selector-spin-wrap">
        <div className="range-selector-spin">
          <button
            type="button"
            className="range-selector-step"
            onClick={() => stepMax(1)}
            aria-label="Augmenter le plus grand nombre"
          >
            ▲
          </button>
          <button
            type="button"
            className="range-selector-step"
            onClick={() => stepMax(-1)}
            disabled={range.max <= range.min + 1}
            aria-label="Diminuer le plus grand nombre"
          >
            ▼
          </button>
        </div>
        <input type="number" value={range.max} onChange={handleMaxChange} aria-label="Plus grand nombre de la plage" />
      </div>
    </div>
  );
}
