import React from 'react';
import { SubjectList } from '../../../components/SubjectList';
import { filterSonsForGrade } from '../../../data/navFilter';
import { useSchoolYear } from '../../../hooks/useSchoolYear';

/** Page de listing des exercices sur les Sons */
export function SonsHome(): React.ReactElement {
  const { grade } = useSchoolYear();
  const items = filterSonsForGrade(grade);
  return <SubjectList title="Les sons" items={items} backPath="/francais" />;
}
