import React from 'react';

interface NumberLineProps {
  start: number;
  end: number;
  /** Nombre de référence marqué d'un point */
  reference: number;
  /** Graduation sélectionnée par l'enfant (null si pas encore répondu) */
  selectedTick: number | null;
  /** Le nombre cible (pour afficher vert/rouge après sélection) */
  target: number;
  /** Indique si la réponse a déjà été donnée */
  answered: boolean;
  /** Appelé quand l'enfant clique sur une graduation */
  onTickClick: (tick: number) => void;
}

/**
 * Échelle graduée SVG interactive.
 * Affiche des graduations cliquables avec le nombre de référence marqué.
 */
export function NumberLine({
  start, end, reference, selectedTick, target, answered, onTickClick,
}: NumberLineProps): React.ReactElement {
  const ticks = [];
  for (let i = start; i <= end; i++) ticks.push(i);

  const width = 100;
  const padding = 5;
  const usableWidth = width - 2 * padding;
  const step = ticks.length > 1 ? usableWidth / (ticks.length - 1) : 0;

  /** Détermine la couleur d'une graduation après la réponse */
  const getTickColor = (tick: number): string => {
    if (!answered) return tick === reference ? '#4A90D9' : '#999';
    if (tick === target) return '#27AE60';
    if (tick === selectedTick && tick !== target) return '#E74C3C';
    if (tick === reference) return '#4A90D9';
    return '#ccc';
  };

  return (
    <svg viewBox={`0 0 ${width} 20`} className="number-line-container" style={{ width: '100%' }}>
      {/* Ligne horizontale */}
      <line x1={padding} y1={10} x2={width - padding} y2={10} stroke="#ccc" strokeWidth="0.5" />

      {ticks.map((tick, i) => {
        const x = padding + i * step;
        const isRef = tick === reference;
        const color = getTickColor(tick);

        return (
          <g key={tick} onClick={() => onTickClick(tick)} style={{ cursor: answered ? 'default' : 'pointer' }}>
            {/* Graduation verticale */}
            <line x1={x} y1={7} x2={x} y2={13} stroke={color} strokeWidth={isRef ? '0.8' : '0.4'} />
            {/* Numéro affiché uniquement sur le point de repère (sinon l'exercice serait de lire les nombres) */}
            {isRef && (
              <text x={x} y={17} textAnchor="middle" className="number-line-tick-label" fill={color} fontWeight="700">
                {tick}
              </text>
            )}
            {/* Après réponse : affiche aussi le nombre cible pour le feedback */}
            {answered && tick === target && tick !== reference && (
              <text x={x} y={17} textAnchor="middle" className="number-line-tick-label" fill={getTickColor(tick)} fontWeight="700">
                {tick}
              </text>
            )}
            {/* Point de référence */}
            {isRef && <circle cx={x} cy={5} r="1.2" fill="#4A90D9" />}
            {/* Zone cliquable invisible (meilleur touch target) */}
            <rect x={x - step / 2} y={0} width={step} height={20} fill="transparent" />
          </g>
        );
      })}
    </svg>
  );
}
