import React from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { Feedback } from '../../../components/Feedback';
import { useExerciseAnswerLimit } from '../../../hooks/useExerciseAnswerLimit';
import { useLettres } from './useLettres';

/**
 * Exercice Lettres : une lettre affichée, trouver sa correspondance
 * majuscule ou minuscule parmi 4 propositions.
 */
export function MajusculesMinuscules(): React.ReactElement {
  const { state, isCorrect, selectChoice, next } = useLettres();
  const { wrapNext } = useExerciseAnswerLimit('/francais');

  /* Consigne adaptée selon la casse affichée */
  const instruction = state.isUpperCase
    ? 'Trouve la minuscule !'
    : 'Trouve la majuscule !';

  return (
    <ExerciseWrapper title="Lettres" backPath="/francais">
      <p style={{ fontSize: 16, color: '#7F8C8D' }}>{instruction}</p>

      {/* Lettre à identifier */}
      <div className="letter-display">{state.displayed}</div>

      {/* 4 choix ou feedback */}
      {isCorrect === null ? (
        <div className="letter-choices">
          {state.choices.map((choice, i) => (
            <button
              key={`${choice}-${i}`}
              className="letter-choice-btn"
              onClick={() => selectChoice(choice)}
            >
              {choice}
            </button>
          ))}
        </div>
      ) : (
        <Feedback
          isCorrect={isCorrect}
          detail={`${state.displayed} → ${state.answer}`}
          onNext={() => wrapNext(next)}
        />
      )}
    </ExerciseWrapper>
  );
}
