import React, { useState, useEffect, useRef } from 'react';
import { GradeSelect } from './GradeSelect';

type OptionsMenuVariant = 'layout' | 'exercise';

interface OptionsMenuProps {
  /** Style du bouton selon l’en-tête (accueil vs exercice) */
  variant: OptionsMenuVariant;
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
}

/**
 * Menu options (⚙️) : choix de la classe, hors du flux pour gagner de la place sur mobile.
 */
export function OptionsMenu({ variant, open: controlledOpen, onOpenChange }: OptionsMenuProps): React.ReactElement {
  const [internalOpen, setInternalOpen] = useState(false);
  const isControlled = controlledOpen !== undefined;
  const open = isControlled ? controlledOpen : internalOpen;
  const setOpen = (value: boolean) => {
    if (!isControlled) setInternalOpen(value);
    onOpenChange?.(value);
  };
  const panelRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!open) return;
    const onKey = (e: KeyboardEvent): void => {
      if (e.key === 'Escape') setOpen(false);
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [open]);

  useEffect(() => {
    if (!open) return;
    const t = window.setTimeout(() => {
      panelRef.current?.querySelector<HTMLElement>('select')?.focus();
    }, 100);
    return () => window.clearTimeout(t);
  }, [open]);

  return (
    <div className="options-menu">
      {!isControlled && (
        <button
          type="button"
          className={`options-menu-trigger options-menu-trigger--${variant}`}
          onClick={() => setOpen(!open)}
          aria-expanded={open}
          aria-haspopup="dialog"
          aria-controls="edmond-options-panel"
          aria-label="Ouvrir le menu options"
        >
          <span className="options-menu-trigger-icon" aria-hidden>
            ⚙️
          </span>
        </button>
      )}

      {open && (
        <>
          <button
            type="button"
            className="options-menu-backdrop"
            aria-label="Fermer le menu"
            onClick={() => setOpen(false)}
          />
          <div
            id="edmond-options-panel"
            ref={panelRef}
            className="options-menu-panel"
            role="dialog"
            aria-modal="true"
            aria-labelledby="edmond-options-title"
          >
            <div className="options-menu-panel-header">
              <h2 id="edmond-options-title" className="options-menu-title">
                Options
              </h2>
              <button
                type="button"
                className="options-menu-close"
                onClick={() => setOpen(false)}
                aria-label="Fermer"
              >
                ✕
              </button>
            </div>
            <div className="options-menu-section">
              <p className="options-menu-section-label">Ma classe</p>
              <GradeSelect variant="panel" onAfterChange={() => setOpen(false)} />
            </div>
          </div>
        </>
      )}
    </div>
  );
}
