import {
  ANAGRAM_SIGNATURE_INDEX,
  ANAGRAM_DICTIONARY_LIST,
  ANAGRAM_PERFECT_FOR_SEED,
} from '../data/sciences/anagram-generated';

/** Supprime les accents (même règle que le script de génération du dictionnaire). */
function stripAccents(s: string): string {
  return s.normalize('NFD').replace(/\p{M}/gu, '');
}

/** Lettres utiles pour les anagrammes : minuscules, sans accents ni ponctuation. */
export function extractLetters(input: string): string {
  const s = stripAccents(input.normalize('NFC').toLowerCase().replace(/\u2019/g, "'"));
  return Array.from(s).filter((ch) => /\p{L}/u.test(ch)).join('');
}

/** Signature pour comparaison d’anagrammes (lettres triées). */
export function wordSignature(letters: string): string {
  return Array.from(letters).sort().join('');
}

/**
 * Tous les mots du dictionnaire ayant exactement les mêmes lettres (hors le mot identique aux lettres saisies).
 */
export function findPerfectAnagrams(input: string): readonly string[] {
  const letters = extractLetters(input);
  if (!letters) return [];
  const sig = wordSignature(letters);
  const bucket = ANAGRAM_SIGNATURE_INDEX[sig];
  if (!bucket?.length) return [];
  return bucket.filter((w) => w !== letters);
}

/** Paires précalculées (liste pédagogique) : autres mots du dictionnaire pour le même lemme. */
const PRECOMPUTED_PEERS = new Map<string, readonly string[]>(
  ANAGRAM_PERFECT_FOR_SEED.map((r) => [r.w, r.a])
);

export function getPrecomputedPerfectPeers(normalizedWord: string): readonly string[] | undefined {
  return PRECOMPUTED_PEERS.get(normalizedWord);
}

function toFreqMap(letters: string): Map<string, number> {
  const m = new Map<string, number>();
  for (const ch of letters) {
    m.set(ch, (m.get(ch) ?? 0) + 1);
  }
  return m;
}

function freqMapIsEmpty(m: Map<string, number>): boolean {
  return !Array.from(m.values()).some((v) => v !== 0);
}

function canSubtractWord(w: string, rem: Map<string, number>): boolean {
  const need = toFreqMap(w);
  return !Array.from(need.entries()).some(([ch, n]) => (rem.get(ch) ?? 0) < n);
}

function subtractWord(w: string, rem: Map<string, number>): Map<string, number> {
  const out = new Map(rem);
  for (const ch of w) {
    out.set(ch, (out.get(ch) ?? 0) - 1);
  }
  return out;
}

function remainingLetterCount(rem: Map<string, number>): number {
  return Array.from(rem.values()).reduce((a, v) => a + v, 0);
}

export interface MultiWordSearchOptions {
  maxSolutions?: number;
  maxWordsInPhrase?: number;
  timeoutMs?: number;
  minWordLength?: number;
}

export interface MultiWordSearchResult {
  /** Phrases d’au moins deux mots (ordre des mots non canonique ; clé triée pour dédoublonner). */
  solutions: string[][];
  timedOut: boolean;
  truncated: boolean;
}

/**
 * Découpages en au moins deux mots du dictionnaire (élagage + limites de temps et de nombre).
 */
export function findMultiWordAnagrams(
  input: string,
  options: MultiWordSearchOptions = {}
): MultiWordSearchResult {
  const maxSolutions = options.maxSolutions ?? 36;
  const maxWords = options.maxWordsInPhrase ?? 8;
  const timeoutMs = options.timeoutMs ?? 420;
  const minWordLength = options.minWordLength ?? 2;

  const letters = extractLetters(input);
  if (!letters) {
    return { solutions: [], timedOut: false, truncated: false };
  }

  const deadline = Date.now() + timeoutMs;
  const solutions: string[][] = [];
  const seen = new Set<string>();
  let timedOut = false;

  function phraseKey(words: string[]): string {
    return [...words].sort().join('|');
  }

  function search(rem: Map<string, number>, path: string[]): void {
    if (solutions.length >= maxSolutions) return;
    if (Date.now() > deadline) {
      timedOut = true;
      return;
    }
    if (freqMapIsEmpty(rem)) {
      if (path.length >= 2) {
        const k = phraseKey(path);
        if (!seen.has(k)) {
          seen.add(k);
          solutions.push([...path]);
        }
      }
      return;
    }
    if (path.length >= maxWords) return;

    const remCount = remainingLetterCount(rem);
    for (const w of ANAGRAM_DICTIONARY_LIST) {
      if (w.length < minWordLength) continue;
      if (w.length > remCount) continue;
      if (!canSubtractWord(w, rem)) continue;
      search(subtractWord(w, rem), [...path, w]);
      if (solutions.length >= maxSolutions || timedOut) return;
    }
  }

  search(toFreqMap(letters), []);

  return {
    solutions,
    timedOut,
    truncated: solutions.length >= maxSolutions,
  };
}
