import { useState, useCallback } from 'react';
import { randomInRange } from '../../../utils/randomInRange';
import { useScore } from '../../../hooks/useScore';

interface ComparisonState {
  a: number;
  b: number;
  /** Le signe correct : '<', '>' ou '=' */
  answer: '<' | '>' | '=';
}

interface UseComparaisonReturn {
  state: ComparisonState;
  isCorrect: boolean | null;
  selectedSign: string | null;
  selectSign: (sign: string) => void;
  next: () => void;
  range: { min: number; max: number };
  updateRange: (r: { min: number; max: number }) => void;
}

/** Génère une comparaison avec ~20% de chance d'avoir des nombres égaux */
function generateComparison(min: number, max: number): ComparisonState {
  const a = randomInRange(min, max);
  /* 20% de chance d'avoir a === b */
  const b = Math.random() < 0.2 ? a : randomInRange(min, max);
  const answer: '<' | '>' | '=' = a > b ? '>' : a < b ? '<' : '=';
  return { a, b, answer };
}

/**
 * Hook pour l'exercice de comparaison (supérieur / inférieur / égal).
 * Gère la génération, la sélection du signe et le score.
 */
export function useComparaison(): UseComparaisonReturn {
  const { addPoint, removePoint } = useScore();
  const [range, setRange] = useState({ min: 1, max: 30 });
  const [state, setState] = useState(() => generateComparison(1, 30));
  const [selectedSign, setSelectedSign] = useState<string | null>(null);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);

  const selectSign = useCallback(
    (sign: string) => {
      if (isCorrect !== null) return;
      setSelectedSign(sign);
      const correct = sign === state.answer;
      setIsCorrect(correct);
      if (correct) addPoint();
      else removePoint();
    },
    [state.answer, isCorrect, addPoint, removePoint]
  );

  const next = useCallback(() => {
    setState(generateComparison(range.min, range.max));
    setSelectedSign(null);
    setIsCorrect(null);
  }, [range]);

  const updateRange = useCallback((r: { min: number; max: number }) => {
    setRange(r);
    setState(generateComparison(r.min, r.max));
    setSelectedSign(null);
    setIsCorrect(null);
  }, []);

  return { state, isCorrect, selectedSign, selectSign, next, range, updateRange };
}
