import React, { useState, useCallback, useMemo } from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { Feedback } from '../../../components/Feedback';
import { useScore } from '../../../hooks/useScore';
import { useExerciseAnswerLimit } from '../../../hooks/useExerciseAnswerLimit';
import {
  FOOD_FAMILIES,
  FOOD_OPTIONS_BY_FAMILY,
  getFamilyById,
} from '../../../data/sciences-nutrition';

const BACK = '/sciences';

type Selections = Record<string, string | null>;

const emptySelections = (): Selections => {
  const s: Selections = {};
  for (const f of FOOD_FAMILIES) s[f.id] = null;
  return s;
};

/** Composer un repas : un choix par famille alimentaire. */
export function RepasEquilibre(): React.ReactElement {
  const { addPoint } = useScore();
  const { wrapNext } = useExerciseAnswerLimit(BACK);
  const [selections, setSelections] = useState<Selections>(emptySelections);
  const [phase, setPhase] = useState<'choose' | 'feedback'>('choose');
  const [isSuccess, setIsSuccess] = useState(false);
  const [missingHint, setMissingHint] = useState<string | null>(null);

  const allChosen = useMemo(
    () => FOOD_FAMILIES.every((f) => selections[f.id] != null),
    [selections]
  );

  const selectOption = useCallback((familyId: string, optionId: string) => {
    if (phase !== 'choose') return;
    setSelections((prev) => ({ ...prev, [familyId]: optionId }));
    setMissingHint(null);
  }, [phase]);

  const validate = useCallback(() => {
    if (!allChosen) {
      const missing = FOOD_FAMILIES.find((f) => selections[f.id] == null);
      setMissingHint(
        missing ? getFamilyById(missing.id)?.hintIfMissing ?? 'Choisis encore un aliment.' : null
      );
      return;
    }
    setIsSuccess(true);
    setPhase('feedback');
    addPoint();
  }, [allChosen, selections, addPoint]);

  const reset = useCallback(() => {
    setSelections(emptySelections());
    setPhase('choose');
    setIsSuccess(false);
    setMissingHint(null);
  }, []);

  const onFeedbackNext = useCallback(() => {
    wrapNext(reset);
  }, [wrapNext, reset]);

  return (
    <ExerciseWrapper title="Repas équilibré" backPath={BACK}>
      <p className="sciences-hint">
        Pour un repas varié, choisis <strong>un aliment dans chaque famille</strong>. Les goûters sucrés sont là
        pour apprendre : une petite part, de temps en temps.
      </p>

      {phase === 'choose' && (
        <>
          <div className="sciences-repas-groups">
            {FOOD_FAMILIES.map((fam) => {
              const options = FOOD_OPTIONS_BY_FAMILY[fam.id] ?? [];
              const selected = selections[fam.id];
              return (
                <div key={fam.id} className="sciences-repas-group">
                  <div className="sciences-repas-group-title">{fam.label}</div>
                  <div className="sciences-repas-options">
                    {options.map((opt) => (
                      <button
                        key={opt.id}
                        type="button"
                        className={`sciences-repas-opt ${selected === opt.id ? 'sciences-repas-opt-on' : ''}`}
                        onClick={() => selectOption(fam.id, opt.id)}
                      >
                        {opt.label}
                      </button>
                    ))}
                  </div>
                </div>
              );
            })}
          </div>
          {missingHint && <p className="sciences-repas-missing">{missingHint}</p>}
          <button
            type="button"
            className="feedback-next"
            onClick={validate}
            disabled={!allChosen}
          >
            Valider mon repas
          </button>
        </>
      )}

      {phase === 'feedback' && (
        <Feedback
          isCorrect={isSuccess}
          detail={
            isSuccess
              ? 'Bravo ! Ton repas mélange plusieurs familles : c’est une bonne habitude pour avoir de l’énergie et des vitamines.'
              : undefined
          }
          onNext={onFeedbackNext}
        />
      )}
    </ExerciseWrapper>
  );
}
