import React, { useState, useCallback, useMemo } from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { Feedback } from '../../../components/Feedback';
import { useExerciseAnswerLimit } from '../../../hooks/useExerciseAnswerLimit';
import { useScore } from '../../../hooks/useScore';
import { FOOD_FAMILIES, FOODS_TO_CLASSIFY } from '../../../data/sciences-nutrition';

const BACK = '/sciences';

function pickFood(excludeLabel: string | null): (typeof FOODS_TO_CLASSIFY)[0] {
  const pool = excludeLabel
    ? FOODS_TO_CLASSIFY.filter((f) => f.label !== excludeLabel)
    : [...FOODS_TO_CLASSIFY];
  return pool[Math.floor(Math.random() * pool.length)] ?? FOODS_TO_CLASSIFY[0];
}

/** Classer un aliment dans la bonne famille alimentaire. */
export function ClasserAliment(): React.ReactElement {
  const { addPoint, removePoint } = useScore();
  const [current, setCurrent] = useState(() => pickFood(null));
  const [feedback, setFeedback] = useState<boolean | null>(null);
  const { wrapNext } = useExerciseAnswerLimit(BACK);

  const nextRound = useCallback(() => {
    setCurrent((c) => pickFood(c.label));
    setFeedback(null);
  }, []);

  const handleFamilyClick = useCallback(
    (familyId: string) => {
      if (feedback !== null) return;
      const ok = familyId === current.familyId;
      setFeedback(ok);
      if (ok) addPoint();
      else removePoint();
    },
    [feedback, current.familyId, addPoint, removePoint]
  );

  const onFeedbackNext = useCallback(() => {
    wrapNext(nextRound);
  }, [wrapNext, nextRound]);

  const detailWrong = useMemo(() => current.tip, [current.tip]);

  return (
    <ExerciseWrapper title="Familles d’aliments" backPath={BACK}>
      <p className="sciences-hint">Dans quelle famille range-t-on cet aliment ?</p>
      <div className="sciences-food-target" aria-live="polite">
        {current.label}
      </div>

      {feedback === null ? (
        <div className="sciences-family-grid" role="group" aria-label="Familles d’aliments">
          {FOOD_FAMILIES.map((fam) => (
            <button
              key={fam.id}
              type="button"
              className="sciences-family-btn"
              onClick={() => handleFamilyClick(fam.id)}
            >
              {fam.label}
            </button>
          ))}
        </div>
      ) : (
        <Feedback
          isCorrect={feedback}
          detail={feedback ? undefined : detailWrong}
          onNext={onFeedbackNext}
        />
      )}
    </ExerciseWrapper>
  );
}
