import { useState, useCallback } from 'react';
import { randomInRange } from '../../../utils/randomInRange';
import { useScore } from '../../../hooks/useScore';

interface NumberLineState {
  /** Début du segment affiché sur l'échelle */
  start: number;
  /** Fin du segment affiché */
  end: number;
  /** Nombre de référence marqué sur l'échelle */
  reference: number;
  /** Nombre à placer (la question) */
  target: number;
}

interface UsePlacerNombreReturn {
  state: NumberLineState;
  isCorrect: boolean | null;
  selectedTick: number | null;
  selectTick: (tick: number) => void;
  next: () => void;
  range: { min: number; max: number };
  updateRange: (r: { min: number; max: number }) => void;
}

/** Génère un état de réglette : un segment de max 15 graduations */
function generateNumberLine(min: number, max: number): NumberLineState {
  /* Taille du segment : entre 8 et 15 graduations */
  const segmentSize = Math.min(randomInRange(8, 15), max - min);
  const start = randomInRange(min, max - segmentSize);
  const end = start + segmentSize;

  /* Deux nombres distincts dans le segment */
  const reference = randomInRange(start, end);
  let target = randomInRange(start, end);
  while (target === reference) {
    target = randomInRange(start, end);
  }

  return { start, end, reference, target };
}

/**
 * Hook pour l'exercice de réglette.
 * Gère la génération du segment, la sélection et la validation.
 */
export function usePlacerNombre(): UsePlacerNombreReturn {
  const { addPoint, removePoint } = useScore();
  const [range, setRange] = useState({ min: 1, max: 30 });
  const [state, setState] = useState(() => generateNumberLine(1, 30));
  const [selectedTick, setSelectedTick] = useState<number | null>(null);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);

  /** L'enfant sélectionne une graduation */
  const selectTick = useCallback(
    (tick: number) => {
      if (isCorrect !== null) return; /* déjà répondu */
      setSelectedTick(tick);
      const correct = tick === state.target;
      setIsCorrect(correct);
      if (correct) addPoint();
      else removePoint();
    },
    [state.target, isCorrect, addPoint, removePoint]
  );

  const next = useCallback(() => {
    setState(generateNumberLine(range.min, range.max));
    setSelectedTick(null);
    setIsCorrect(null);
  }, [range]);

  const updateRange = useCallback((r: { min: number; max: number }) => {
    setRange(r);
    setState(generateNumberLine(r.min, r.max));
    setSelectedTick(null);
    setIsCorrect(null);
  }, []);

  return { state, isCorrect, selectedTick, selectTick, next, range, updateRange };
}
