/**
 * Définitions des formes géométriques pour l'exercice de reconnaissance.
 * Chaque forme est dessinée en SVG dans un viewBox de 200x200.
 */

export interface ShapeDefinition {
  id: string;
  name: string;
  /** Type d'élément SVG à rendre */
  svgElement: 'rect' | 'polygon' | 'circle' | 'ellipse';
  /** Propriétés SVG de la forme */
  props: Record<string, string | number>;
}

