/**
 * Repérage sur quadrillage : déplacements haut / bas / gauche / droite.
 * Coordonnées : ligne 0 en haut, colonne 0 à gauche.
 */

export type CoccinelleArrivalColor = 'red' | 'green' | 'yellow';

export type CoccinelleDir = 'up' | 'down' | 'left' | 'right';

export interface CoccinelleMove {
  dir: CoccinelleDir;
  steps: number;
}

export interface CoccinelleGrilleExercise {
  /** Niveau de difficulté 1–3 */
  level: 1 | 2 | 3;
  rows: number;
  cols: number;
  startRow: number;
  startCol: number;
  endRow: number;
  endCol: number;
  moves: CoccinelleMove[];
  arrivalColor: CoccinelleArrivalColor;
  frameColor: string;
  instruction: string;
}

const DELTA: Record<CoccinelleDir, [number, number]> = {
  up: [-1, 0],
  down: [1, 0],
  left: [0, -1],
  right: [0, 1],
};

const DIR_LABEL: Record<CoccinelleDir, string> = {
  up: 'le haut',
  down: 'le bas',
  left: 'la gauche',
  right: 'la droite',
};

const LEVEL_STYLE: Record<
  1 | 2 | 3,
  { arrivalColor: CoccinelleArrivalColor; frameColor: string; colorName: string }
> = {
  1: { arrivalColor: 'red', frameColor: '#3498db', colorName: 'rouge' },
  2: { arrivalColor: 'green', frameColor: '#f39c12', colorName: 'vert' },
  3: { arrivalColor: 'yellow', frameColor: '#e74c3c', colorName: 'jaune' },
};

function movePhrase(dir: CoccinelleDir, steps: number): string {
  const w = DIR_LABEL[dir];
  if (steps === 1) return `d'une case vers ${w}`;
  return `de ${steps} cases vers ${w}`;
}

function buildInstruction(moves: CoccinelleMove[], colorName: string): string {
  const parts = moves.map((m) => movePhrase(m.dir, m.steps));
  let body: string;
  if (parts.length === 1) {
    body = `se déplace ${parts[0]}`;
  } else if (parts.length === 2) {
    body = `se déplace ${parts[0]}, puis ${parts[1]}`;
  } else {
    const last = parts.pop()!;
    body = `se déplace ${parts.join(', ')}, et enfin ${last}`;
  }
  return `La coccinelle ${body}. Colorie en ${colorName} la case d'arrivée.`;
}

/** Nombre de segments de déplacement selon le niveau. */
function moveCountForLevel(level: 1 | 2 | 3): number {
  if (level === 1) return 2;
  if (level === 2) return 3;
  return 4;
}

/** Pas max par segment (grille petite au niveau 1). */
function maxStepCap(level: 1 | 2 | 3, maxInGrid: number): number {
  const cap = level === 1 ? 2 : 3;
  return Math.min(maxInGrid, cap);
}

/**
 * Génère un parcours valide aléatoire. `rng` doit renvoyer [0, 1).
 */
export function generateCoccinelleExercise(
  level: 1 | 2 | 3,
  rng: () => number
): CoccinelleGrilleExercise {
  const rows = level === 1 ? 3 : 4;
  const cols = rows;
  const nMoves = moveCountForLevel(level);
  const dirs: CoccinelleDir[] = ['up', 'down', 'left', 'right'];

  for (let attempt = 0; attempt < 400; attempt += 1) {
    let r = Math.floor(rng() * rows);
    let c = Math.floor(rng() * cols);
    const startRow = r;
    const startCol = c;
    const moves: CoccinelleMove[] = [];
    let failed = false;

    for (let i = 0; i < nMoves; i += 1) {
      const candidates: { dir: CoccinelleDir; maxS: number }[] = [];
      if (r > 0) candidates.push({ dir: 'up', maxS: r });
      if (r < rows - 1) candidates.push({ dir: 'down', maxS: rows - 1 - r });
      if (c > 0) candidates.push({ dir: 'left', maxS: c });
      if (c < cols - 1) candidates.push({ dir: 'right', maxS: cols - 1 - c });

      if (candidates.length === 0) {
        failed = true;
        break;
      }

      const pick = candidates[Math.floor(rng() * candidates.length)];
      const cap = maxStepCap(level, pick.maxS);
      if (cap < 1) {
        failed = true;
        break;
      }
      const steps = 1 + Math.floor(rng() * cap);
      const [dr, dc] = DELTA[pick.dir];
      r += dr * steps;
      c += dc * steps;
      moves.push({ dir: pick.dir, steps });
    }

    if (!failed) {
      const style = LEVEL_STYLE[level];
      return {
        level,
        rows,
        cols,
        startRow,
        startCol,
        endRow: r,
        endCol: c,
        moves,
        arrivalColor: style.arrivalColor,
        frameColor: style.frameColor,
        instruction: buildInstruction(moves, style.colorName),
      };
    }
  }

  /* Secours déterministe (ne devrait pas arriver) */
  const style = LEVEL_STYLE[level];
  if (level === 1) {
    return {
      level: 1,
      rows: 3,
      cols: 3,
      startRow: 2,
      startCol: 0,
      endRow: 1,
      endCol: 2,
      moves: [
        { dir: 'up', steps: 1 },
        { dir: 'right', steps: 2 },
      ],
      arrivalColor: style.arrivalColor,
      frameColor: style.frameColor,
      instruction: buildInstruction(
        [
          { dir: 'up', steps: 1 },
          { dir: 'right', steps: 2 },
        ],
        style.colorName
      ),
    };
  }
  if (level === 2) {
    return {
      level: 2,
      rows: 4,
      cols: 4,
      startRow: 2,
      startCol: 0,
      endRow: 1,
      endCol: 1,
      moves: [
        { dir: 'right', steps: 3 },
        { dir: 'up', steps: 1 },
        { dir: 'left', steps: 2 },
      ],
      arrivalColor: style.arrivalColor,
      frameColor: style.frameColor,
      instruction: buildInstruction(
        [
          { dir: 'right', steps: 3 },
          { dir: 'up', steps: 1 },
          { dir: 'left', steps: 2 },
        ],
        style.colorName
      ),
    };
  }
  return {
    level: 3,
    rows: 4,
    cols: 4,
    startRow: 2,
    startCol: 2,
    endRow: 0,
    endCol: 2,
    moves: [
      { dir: 'left', steps: 2 },
      { dir: 'up', steps: 2 },
      { dir: 'right', steps: 2 },
      { dir: 'down', steps: 2 },
    ],
    arrivalColor: style.arrivalColor,
    frameColor: style.frameColor,
    instruction: buildInstruction(
      [
        { dir: 'left', steps: 2 },
        { dir: 'up', steps: 2 },
        { dir: 'right', steps: 2 },
        { dir: 'down', steps: 2 },
      ],
      style.colorName
    ),
  };
}
