import React, { useState, useCallback, useRef, useEffect } from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { AnalogClock } from '../../../components/sciences/AnalogClock';
import { addClock12Minutes, formatDigital12 } from '../../../utils/clock12';

const BACK = '/sciences';

/** Attente avant répétition continue (évite le double pas au tap court). */
const HOLD_DELAY_MS = 400;
/** 5 minutes sur l’horloge par seconde réelle : un pas de 1 min toutes les 200 ms. */
const REPEAT_INTERVAL_MS = 200;

/**
 * Boutons − / + : un tap avance ou recule d’une minute ; maintenir appuyé répète à 5 min/s.
 */
export function HorlogeEntrainement(): React.ReactElement {
  const [clock, setClock] = useState({ hour12: 3, minute: 0 });

  const adjust = useCallback((delta: number) => {
    setClock(({ hour12, minute }) => {
      const r = addClock12Minutes(hour12, minute, delta);
      return { hour12: r.hour12, minute: r.minute };
    });
  }, []);

  return (
    <ExerciseWrapper title="Horloge d’entraînement" backPath={BACK}>
      <p className="sciences-hint">
        Regarde le cadran et l’heure en chiffres. Touche <strong>−</strong> ou <strong>+</strong> pour changer d’une
        minute. Si tu gardes le doigt appuyé, l’horloge défile plus vite (5 minutes sur le cadran par seconde).
      </p>

      <div className="sciences-clock-train sciences-clock-train--solo">
        <div className="sciences-clock-train-row">
          <AnalogClock hour12={clock.hour12} minute={clock.minute} hideMinuteHand={false} />
          <div className="sciences-clock-train-side">
            <p className="sciences-clock-train-digital" aria-live="polite">
              {formatDigital12(clock.hour12, clock.minute)}
            </p>
            <div className="sciences-clock-train-controls">
              <MinuteStepButton delta={-1} onStep={adjust} label="Reculer d’une minute" symbol="−" />
              <MinuteStepButton delta={1} onStep={adjust} label="Avancer d’une minute" symbol="+" />
            </div>
          </div>
        </div>
      </div>
    </ExerciseWrapper>
  );
}

interface MinuteStepButtonProps {
  delta: number;
  onStep: (delta: number) => void;
  label: string;
  symbol: string;
}

function MinuteStepButton({ delta, onStep, label, symbol }: MinuteStepButtonProps): React.ReactElement {
  const delayRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const clearHold = useCallback(() => {
    if (delayRef.current !== null) {
      clearTimeout(delayRef.current);
      delayRef.current = null;
    }
    if (intervalRef.current !== null) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
  }, []);

  const startHold = useCallback(() => {
    onStep(delta);
    delayRef.current = setTimeout(() => {
      delayRef.current = null;
      intervalRef.current = setInterval(() => onStep(delta), REPEAT_INTERVAL_MS);
    }, HOLD_DELAY_MS);
  }, [delta, onStep]);

  useEffect(() => () => clearHold(), [clearHold]);

  return (
    <button
      type="button"
      className="sciences-clock-train-step"
      aria-label={label}
      onPointerDown={(e) => {
        if (e.button !== 0) return;
        e.preventDefault();
        startHold();
      }}
      onPointerUp={clearHold}
      onPointerCancel={clearHold}
      onPointerLeave={clearHold}
      onKeyDown={(e) => {
        if (e.key !== 'Enter' && e.key !== ' ') return;
        if (e.repeat) return;
        e.preventDefault();
        onStep(delta);
      }}
      onClick={(e) => e.preventDefault()}
    >
      {symbol}
    </button>
  );
}
