import React from 'react';
import { HashRouter, Routes, Route } from 'react-router-dom';
import { ScoreProvider } from './hooks/useScore';
import { SchoolYearProvider } from './hooks/useSchoolYear';
import { Layout } from './components/Layout';
import { GradeRouteSync } from './components/GradeRouteSync';
import './App.css';

/* Pages de navigation */
import { Home } from './pages/Home';
import { MathsHome } from './pages/maths/MathsHome';
import { CalculsHome } from './pages/maths/calculs/CalculsHome';
import { FrancaisHome } from './pages/francais/FrancaisHome';
import { GeometrieHome } from './pages/maths/geometrie/GeometrieHome';
import { SonsHome } from './pages/francais/sons/SonsHome';
import { SciencesHome } from './pages/sciences/SciencesHome';
import { RepasEquilibre } from './pages/sciences/nutrition/RepasEquilibre';
import { ClasserAliment } from './pages/sciences/nutrition/ClasserAliment';
import { LireHeure } from './pages/sciences/temps/LireHeure';
import { HorlogeEntrainement } from './pages/sciences/temps/HorlogeEntrainement';
import { ElectriciteJeu } from './pages/sciences/electricite/ElectriciteJeu';
import { Anagrammes } from './pages/sciences/anagrammes/Anagrammes';

/* Exercices Maths — Calculs */
import { Addition } from './pages/maths/calculs/addition';
import { Soustraction } from './pages/maths/calculs/soustraction';
import { Multiplication } from './pages/maths/calculs/multiplication';
import { Division } from './pages/maths/calculs/division';
import { Probleme } from './pages/maths/calculs/probleme';
import { TransformationProblemes } from './pages/maths/calculs/transformation';

/* Exercices Maths — Autres thèmes */
import { PlacerNombre } from './pages/maths/reglette';
import { SuperieurInferieur } from './pages/maths/comparaison';
import { DizainesEncadrement } from './pages/maths/dizaines';
import { Formes } from './pages/maths/geometrie';
import { TrouveFormes } from './pages/maths/geometrie/TrouveFormes';
import { CoccinellesGrilles } from './pages/maths/coccinelles';

/* Exercices Français */
import { MajusculesMinuscules } from './pages/francais/lettres';
import { DecoupeEnSons } from './pages/francais/sons';
import { TrouveSon } from './pages/francais/sons/TrouveSon';
import { Pendu } from './pages/francais/pendu';
import { TrouveArticle, EntoureDeterminant } from './pages/francais/articles';
import { ComposeMots } from './pages/francais/compose';
import { DevinettesMotsComposes } from './pages/francais/devinettes';

/**
 * Composant racine de l'application Edmond.
 * Utilise HashRouter pour la compatibilité GitHub Pages.
 * Le ScoreProvider englobe toute l'app pour un score global persistant.
 */
function App(): React.ReactElement {
  return (
    <HashRouter>
      <SchoolYearProvider>
        <ScoreProvider>
          <GradeRouteSync />
          <Routes>
            {/* Pages de navigation — avec Layout (header + score) */}
            <Route element={<Layout />}>
              <Route index element={<Home />} />
              <Route path="maths" element={<MathsHome />} />
              <Route path="maths/calculs" element={<CalculsHome />} />
              <Route path="maths/geometrie" element={<GeometrieHome />} />
              <Route path="francais" element={<FrancaisHome />} />
              <Route path="francais/sons" element={<SonsHome />} />
              <Route path="sciences" element={<SciencesHome />} />
            </Route>

            {/* Exercices Maths — Calculs */}
            <Route path="maths/calculs/addition" element={<Addition />} />
            <Route path="maths/calculs/soustraction" element={<Soustraction />} />
            <Route path="maths/calculs/multiplication" element={<Multiplication />} />
            <Route path="maths/calculs/division" element={<Division />} />
            <Route path="maths/calculs/probleme" element={<Probleme />} />
            <Route path="maths/calculs/transformation" element={<TransformationProblemes />} />

            {/* Exercices Maths — Réglette, Comparaison */}
            <Route path="maths/reglette" element={<PlacerNombre />} />
            <Route path="maths/comparaison" element={<SuperieurInferieur />} />
            <Route path="maths/dizaines" element={<DizainesEncadrement />} />
            <Route path="maths/coccinelles" element={<CoccinellesGrilles />} />

            {/* Exercices Maths — Géométrie (2 exercices) */}
            <Route path="maths/geometrie/reconnaissance" element={<Formes />} />
            <Route path="maths/geometrie/trouve" element={<TrouveFormes />} />

            {/* Exercices Français — Lettres */}
            <Route path="francais/lettres" element={<MajusculesMinuscules />} />
            <Route path="francais/trouve-article" element={<TrouveArticle />} />
            <Route path="francais/entoure-determinant" element={<EntoureDeterminant />} />
            <Route path="francais/compose-mots" element={<ComposeMots />} />
            <Route path="francais/devinettes-mots" element={<DevinettesMotsComposes />} />

            <Route path="francais/pendu" element={<Pendu />} />

            {/* Exercices Français — Sons (2 exercices) */}
            <Route path="francais/sons/decoupe" element={<DecoupeEnSons />} />
            <Route path="francais/sons/trouve" element={<TrouveSon />} />

            <Route path="sciences/nutrition/repas" element={<RepasEquilibre />} />
            <Route path="sciences/nutrition/familles" element={<ClasserAliment />} />
            <Route path="sciences/temps/heure" element={<LireHeure />} />
            <Route path="sciences/temps/horloge-entrainement" element={<HorlogeEntrainement />} />
            <Route path="sciences/electricite/jeu" element={<ElectriciteJeu />} />
            <Route path="sciences/anagrammes" element={<Anagrammes />} />
          </Routes>
        </ScoreProvider>
      </SchoolYearProvider>
    </HashRouter>
  );
}

export default App;
