import React from 'react';
import { ShapeDefinition } from '../../../data/formes';

interface ShapeRendererProps {
  shape: ShapeDefinition;
  color: string;
  /** Rotation en degrés pour varier la difficulté */
  rotation: number;
}

/**
 * Dessine une forme géométrique en SVG.
 * Supporte : rect, polygon, circle, ellipse.
 */
export function ShapeRenderer({ shape, color, rotation }: ShapeRendererProps): React.ReactElement {
  /** Crée l'élément SVG correspondant au type de la forme */
  const renderShape = (): React.ReactElement => {
    const commonProps = {
      fill: color,
      stroke: '#333',
      strokeWidth: 2,
      ...shape.props,
    };

    switch (shape.svgElement) {
      case 'rect':
        return <rect {...commonProps} />;
      case 'polygon':
        return <polygon {...commonProps} />;
      case 'circle':
        return <circle {...commonProps} />;
      case 'ellipse':
        return <ellipse {...commonProps} />;
    }
  };

  return (
    <svg viewBox="0 0 200 200" width="180" height="180">
      <g transform={`rotate(${rotation}, 100, 100)`}>
        {renderShape()}
      </g>
    </svg>
  );
}
