import React, { useCallback, useMemo, useState } from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { COMPOSE_MOTS_PAIRS } from '../../../data/compose-mots-pairs';

function shuffle<T>(arr: T[]): T[] {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i -= 1) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

/**
 * Relier les mots deux à deux (colonne de droite mélangée).
 */
export function ComposeMots(): React.ReactElement {
  const optionOrder = useMemo(
    () => shuffle(COMPOSE_MOTS_PAIRS.map((p) => p.right)),
    []
  );

  const [picks, setPicks] = useState<string[]>(() => COMPOSE_MOTS_PAIRS.map(() => ''));
  const [feedback, setFeedback] = useState<'idle' | 'ok' | 'err'>('idle');
  const [errDetail, setErrDetail] = useState<string | null>(null);
  const [rowOk, setRowOk] = useState<boolean[] | null>(null);

  const resetRound = useCallback(() => {
    setPicks(COMPOSE_MOTS_PAIRS.map(() => ''));
    setFeedback('idle');
    setErrDetail(null);
    setRowOk(null);
  }, []);

  const verify = useCallback(() => {
    const picked = picks.map((p) => p.trim());
    if (picked.some((p) => !p)) {
      setFeedback('err');
      setErrDetail('Choisis un mot de la colonne de droite pour chaque ligne.');
      setRowOk(null);
      return;
    }

    const useCount = new Map<string, number>();
    for (const p of picked) {
      useCount.set(p, (useCount.get(p) ?? 0) + 1);
    }
    if (useCount.size !== picked.length) {
      setFeedback('err');
      setErrDetail('Chaque mot de droite ne peut être utilisé qu’une seule fois.');
      setRowOk(null);
      return;
    }

    const perRow: boolean[] = COMPOSE_MOTS_PAIRS.map((pair, i) => picked[i] === pair.right);

    setRowOk(perRow);

    if (perRow.every(Boolean)) {
      setFeedback('ok');
      setErrDetail(null);
    } else {
      setFeedback('err');
      setErrDetail('Vérifie les associations.');
    }
  }, [picks]);

  const setPick = (index: number, v: string) => {
    setPicks((prev) => {
      const next = [...prev];
      next[index] = v;
      return next;
    });
    setFeedback('idle');
    setErrDetail(null);
    setRowOk(null);
  };

  return (
    <ExerciseWrapper title="Compose les mots" backPath="/francais">
      <div className="compose-mots-sheet">
        <div className="compose-mots-head">
          <h1 className="compose-mots-title">Compose les mots</h1>
          <p className="compose-mots-instruction">
            Relie les mots deux à deux : pour chaque mot de gauche, choisis sa suite dans la liste à droite.
          </p>
          <p className="compose-mots-hint">
            Chaque mot de droite ne s&apos;utilise qu&apos;une fois.
          </p>
        </div>

        <div className="compose-mots-example">
          <strong>Exemple</strong> : <span className="compose-mots-example-join">pique</span> se relie à{' '}
          <span className="compose-mots-example-join">nique</span> (mot composé :{' '}
          <span className="compose-mots-example-word">pique-nique</span>).
        </div>

        <div className="compose-mots-rows" role="list">
          {COMPOSE_MOTS_PAIRS.map((pair, i) => {
            const rowClass =
              rowOk === null
                ? ''
                : rowOk[i]
                  ? ' compose-mots-row-ok'
                  : ' compose-mots-row-err';

            return (
              <div className={`compose-mots-row${rowClass}`} role="listitem" key={`${pair.left}-${pair.right}`}>
                <div className="compose-mots-cell-left">
                  <span className="compose-mots-dot" aria-hidden />
                  <span className="compose-mots-left-word">{pair.left}</span>
                </div>
                <span className="compose-mots-cell-dot" aria-hidden>
                  ·
                </span>
                <div className="compose-mots-cell-select">
                  <label className="visually-hidden" htmlFor={`compose-pick-${i}`}>
                    Mot associé à « {pair.left} »
                  </label>
                  <select
                    id={`compose-pick-${i}`}
                    className="compose-mots-select"
                    value={picks[i]}
                    onChange={(e) => setPick(i, e.target.value)}
                  >
                    <option value="">— ? —</option>
                    {optionOrder.map((w) => (
                      <option key={w} value={w}>
                        {w}
                      </option>
                    ))}
                  </select>
                </div>
              </div>
            );
          })}
        </div>

        <footer className="compose-mots-footer">
          {feedback === 'ok' ? (
            <p className="compose-mots-success" role="status">
              Bravo ! Toutes les associations sont justes.
            </p>
          ) : null}
          {feedback === 'err' && errDetail ? (
            <p className="compose-mots-error" role="alert">
              {errDetail}
            </p>
          ) : null}
          <div className="compose-mots-actions">
            <button type="button" className="compose-mots-btn compose-mots-btn-primary" onClick={verify}>
              Vérifier
            </button>
            <button type="button" className="compose-mots-btn" onClick={resetRound}>
              Recommencer
            </button>
          </div>
        </footer>
      </div>
    </ExerciseWrapper>
  );
}
