import React, { useEffect, useRef, useState } from 'react';
import { useScore } from '../hooks/useScore';

/**
 * Affichage animé du score.
 * Pulse en vert quand le score monte, en rouge quand il descend.
 */
export function ScoreDisplay(): React.ReactElement {
  const { score } = useScore();
  const prevScore = useRef(score);
  const [animation, setAnimation] = useState<'pulse-up' | 'pulse-down' | ''>('');

  useEffect(() => {
    if (score > prevScore.current) {
      setAnimation('pulse-up');
    } else if (score < prevScore.current) {
      setAnimation('pulse-down');
    }
    prevScore.current = score;

    /* Retire l'animation après 300ms */
    const timer = setTimeout(() => setAnimation(''), 300);
    return () => clearTimeout(timer);
  }, [score]);

  return (
    <span className={`score-display ${animation}`}>
      ⭐ {score}
    </span>
  );
}
