import React, { useMemo, useState, useCallback } from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import {
  extractLetters,
  findPerfectAnagrams,
  findMultiWordAnagrams,
  getPrecomputedPerfectPeers,
} from '../../../utils/anagram';

const BACK = '/sciences';

/** Affiche une solution multi-mots lisible. */
function formatPhrase(words: readonly string[]): string {
  return words.join(' + ');
}

/** Calculateur d’anagrammes (dictionnaire primaire + extensions locales générées). */
export function Anagrammes(): React.ReactElement {
  const [raw, setRaw] = useState('');
  const [submitted, setSubmitted] = useState('');

  const letters = useMemo(() => extractLetters(submitted), [submitted]);

  const perfect = useMemo(() => (submitted.trim() ? findPerfectAnagrams(submitted) : []), [submitted]);

  const multi = useMemo(() => {
    if (!submitted.trim() || letters.length < 4) {
      return { solutions: [] as string[][], timedOut: false, truncated: false };
    }
    return findMultiWordAnagrams(submitted);
  }, [submitted, letters.length]);

  const onSubmit = useCallback(
    (e: React.FormEvent) => {
      e.preventDefault();
      setSubmitted(raw);
    },
    [raw]
  );

  return (
    <ExerciseWrapper title="Anagrammes" backPath={BACK}>
      <p className="sciences-hint">
        Tape des lettres ou un mot : on cherche d’autres mots avec les mêmes lettres (les accents ne comptent
        pas), puis des découpages en plusieurs mots (dictionnaire limité, comme au primaire).
      </p>

      <form className="sciences-anagram-form" onSubmit={onSubmit}>
        <label htmlFor="anagram-input" className="sciences-anagram-label">
          Texte
        </label>
        <input
          id="anagram-input"
          type="text"
          className="sciences-anagram-input"
          value={raw}
          onChange={(e) => setRaw(e.target.value)}
          placeholder="Ex. chien, gare, ou une phrase"
          autoComplete="off"
          spellCheck={false}
        />
        <button type="submit" className="sciences-anagram-submit">
          Chercher
        </button>
      </form>

      {submitted.trim() !== '' && (
        <div className="sciences-anagram-results">
          <p className="sciences-anagram-letters">
            Lettres utilisées : <strong>{letters || '—'}</strong>
            {letters.length > 0 && <span className="sciences-anagram-meta"> ({letters.length} lettres)</span>}
          </p>

          <section className="sciences-anagram-block" aria-labelledby="anagram-perfect-heading">
            <h2 id="anagram-perfect-heading" className="sciences-anagram-heading">
              Un seul mot (mêmes lettres)
            </h2>
            {letters.length === 0 ? (
              <p className="sciences-anagram-empty">Aucune lettre à analyser.</p>
            ) : perfect.length === 0 ? (
              <p className="sciences-anagram-empty">Aucun autre mot du dictionnaire avec exactement ces lettres.</p>
            ) : (
              <ul className="sciences-anagram-list">
                {perfect.map((w) => (
                  <li key={w}>{w}</li>
                ))}
              </ul>
            )}
            {letters.length > 0 && getPrecomputedPerfectPeers(letters) !== undefined && (
              <p className="sciences-anagram-note">
                Ce mot figure dans la banque d’anagrammes précalculée du projet (générée avec le script local).
              </p>
            )}
          </section>

          <section className="sciences-anagram-block" aria-labelledby="anagram-multi-heading">
            <h2 id="anagram-multi-heading" className="sciences-anagram-heading">
              Plusieurs mots ensemble
            </h2>
            {letters.length < 4 ? (
              <p className="sciences-anagram-empty">Entre au moins 4 lettres pour lancer cette recherche.</p>
            ) : multi.solutions.length === 0 ? (
              <p className="sciences-anagram-empty">
                {multi.timedOut
                  ? 'Recherche interrompue (trop de possibilités). Réessaie avec moins de lettres ou un autre texte.'
                  : 'Aucune combinaison d’au moins deux mots du dictionnaire ne reprend toutes ces lettres.'}
              </p>
            ) : (
              <>
                <ul className="sciences-anagram-list sciences-anagram-list--phrases">
                  {multi.solutions.map((words) => (
                    <li key={formatPhrase(words)}>{formatPhrase(words)}</li>
                  ))}
                </ul>
                {(multi.timedOut || multi.truncated) && (
                  <p className="sciences-anagram-note">
                    {multi.truncated && 'Résultats limités pour rester rapide. '}
                    {multi.timedOut && 'Temps de recherche dépassé sur cette entrée.'}
                  </p>
                )}
              </>
            )}
          </section>
        </div>
      )}
    </ExerciseWrapper>
  );
}
