import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
  ReactNode,
} from 'react';
import type { SchoolYear } from '../data/schoolYear';
import { isSchoolYear, SCHOOL_YEAR_STORAGE_KEY } from '../data/schoolYear';
import { getAvailableSchoolYears } from '../data/navFilter';

interface SchoolYearContextValue {
  grade: SchoolYear;
  setGrade: (y: SchoolYear) => void;
  /** Années proposées dans le menu (au moins un exercice existe) */
  availableYears: SchoolYear[];
}

const SchoolYearContext = createContext<SchoolYearContextValue | null>(null);

function readInitialSchoolYear(available: SchoolYear[]): SchoolYear {
  try {
    const raw = localStorage.getItem(SCHOOL_YEAR_STORAGE_KEY);
    if (raw && isSchoolYear(raw) && available.includes(raw)) return raw;
  } catch {
    /* ignore */
  }
  return available[0] ?? 'CP';
}

export function SchoolYearProvider({ children }: { children: ReactNode }): React.ReactElement {
  const availableYears = useMemo(() => getAvailableSchoolYears(), []);

  const [grade, setGradeState] = useState<SchoolYear>(() =>
    readInitialSchoolYear(availableYears)
  );

  useEffect(() => {
    if (!availableYears.includes(grade)) {
      const fallback = availableYears[0] ?? 'CP';
      setGradeState(fallback);
      try {
        localStorage.setItem(SCHOOL_YEAR_STORAGE_KEY, fallback);
      } catch {
        /* ignore */
      }
    }
  }, [availableYears, grade]);

  const setGrade = useCallback(
    (y: SchoolYear) => {
      if (!availableYears.includes(y)) return;
      setGradeState(y);
      try {
        localStorage.setItem(SCHOOL_YEAR_STORAGE_KEY, y);
      } catch {
        /* ignore */
      }
    },
    [availableYears]
  );

  const value = useMemo(
    () => ({ grade, setGrade, availableYears }),
    [grade, setGrade, availableYears]
  );

  return <SchoolYearContext.Provider value={value}>{children}</SchoolYearContext.Provider>;
}

export function useSchoolYear(): SchoolYearContextValue {
  const ctx = useContext(SchoolYearContext);
  if (!ctx) {
    throw new Error('useSchoolYear must be used within SchoolYearProvider');
  }
  return ctx;
}
