import React from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { RangeSelector } from '../../../components/RangeSelector';
import { Feedback } from '../../../components/Feedback';
import { useExerciseAnswerLimit } from '../../../hooks/useExerciseAnswerLimit';
import { NumberLine } from './NumberLine';
import { usePlacerNombre } from './usePlacerNombre';

/**
 * Exercice Réglette : placer un nombre sur une échelle graduée.
 * Un nombre de référence est marqué, l'enfant doit cliquer sur le bon emplacement.
 */
export function PlacerNombre(): React.ReactElement {
  const { state, isCorrect, selectedTick, selectTick, next, range, updateRange } =
    usePlacerNombre();
  const { wrapNext } = useExerciseAnswerLimit('/maths');

  return (
    <ExerciseWrapper title="Réglette" backPath="/maths">
      <RangeSelector range={range} onChange={updateRange} />

      {/* Consigne */}
      <div className="number-line-target">
        Où est le <strong>{state.target}</strong> ?
      </div>

      {/* Échelle graduée interactive */}
      <NumberLine
        start={state.start}
        end={state.end}
        reference={state.reference}
        selectedTick={selectedTick}
        target={state.target}
        answered={isCorrect !== null}
        onTickClick={selectTick}
      />

      {/* Feedback après réponse */}
      {isCorrect !== null && (
        <Feedback isCorrect={isCorrect} onNext={() => wrapNext(next)} />
      )}
    </ExerciseWrapper>
  );
}
