import React from 'react';
import { SubjectList } from '../../components/SubjectList';
import { filterFrancaisThemesForGrade } from '../../data/navFilter';
import { useSchoolYear } from '../../hooks/useSchoolYear';

/** Page Français : choix entre Lettres et Sons */
export function FrancaisHome(): React.ReactElement {
  const { grade } = useSchoolYear();
  const items = filterFrancaisThemesForGrade(grade);
  return <SubjectList title="Français" items={items} backPath="/" />;
}
