import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useSchoolYear } from '../hooks/useSchoolYear';

export interface GradeSelectProps {
  /** `panel` : styles pour le menu options (fond clair) */
  variant?: 'default' | 'panel';
  /** Après changement de classe (navigation vers l’accueil incluse) */
  onAfterChange?: () => void;
}

/**
 * Menu classe (CP → CM2), persisté via SchoolYearProvider / localStorage.
 * Le changement renvoie à l'accueil pour éviter une page de liste vide.
 */
export function GradeSelect({
  variant = 'default',
  onAfterChange,
}: GradeSelectProps): React.ReactElement {
  const { grade, setGrade, availableYears } = useSchoolYear();
  const navigate = useNavigate();

  if (availableYears.length <= 1) {
    return (
      <span
        className={
          variant === 'panel' ? 'grade-select-label grade-select-label--panel' : 'grade-select-label'
        }
        title="Classe"
      >
        {grade}
      </span>
    );
  }

  const wrapClass =
    variant === 'panel' ? 'grade-select-wrap grade-select-wrap--panel' : 'grade-select-wrap';
  const selectClass = variant === 'panel' ? 'grade-select grade-select--panel' : 'grade-select';

  return (
    <label className={wrapClass}>
      <span className="grade-select-sr">Classe</span>
      <select
        className={selectClass}
        value={grade}
        aria-label="Choisir la classe"
        onChange={(e) => {
          const y = e.target.value as typeof grade;
          setGrade(y);
          navigate('/');
          onAfterChange?.();
        }}
      >
        {availableYears.map((y) => (
          <option key={y} value={y}>
            {y}
          </option>
        ))}
      </select>
    </label>
  );
}
