import { randomInRange } from './randomInRange';

/** Opérateurs mathématiques supportés */
export type Operator = '+' | '-' | '×' | '÷';

/** Résultat d'une opération générée avec un nombre manquant */
export interface GeneratedOperation {
  a: number;
  b: number;
  result: number;
  /** Index du nombre caché : 0 = a, 1 = b, 2 = résultat */
  missingIndex: 0 | 1 | 2;
  /** La bonne réponse (le nombre caché) */
  answer: number;
  operator: Operator;
}

/**
 * Génère une opération mathématique avec un nombre manquant.
 * Garantit des résultats positifs et entiers.
 *
 * - Addition : le résultat reste dans [min, max]
 * - Soustraction : a > b, résultat positif
 * - Multiplication : opérandes dans [min, max]
 * - Division : division exacte, pas de reste
 */
export function generateOperation(
  operator: Operator,
  min: number,
  max: number
): GeneratedOperation {
  let a: number, b: number, result: number;

  switch (operator) {
    case '+': {
      /* Génère le résultat d'abord, puis le décompose */
      result = randomInRange(min + 1, max);
      a = randomInRange(1, result - 1);
      b = result - a;
      break;
    }
    case '-': {
      /* Génère a (le plus grand), puis b plus petit */
      a = randomInRange(min + 1, max);
      b = randomInRange(1, a - 1);
      result = a - b;
      break;
    }
    case '×': {
      a = randomInRange(min, max);
      b = randomInRange(min, max);
      result = a * b;
      break;
    }
    case '÷': {
      /* Génère le diviseur et le quotient, puis calcule le dividende */
      b = randomInRange(Math.max(min, 1), max);
      result = randomInRange(min, max);
      a = b * result;
      break;
    }
  }

  /* Choisit aléatoirement quel nombre cacher */
  const missingIndex = randomInRange(0, 2) as 0 | 1 | 2;
  const answer = [a, b, result][missingIndex];

  return { a, b, result, missingIndex, answer, operator };
}
