import React, { useCallback, useMemo, useState } from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { DEVINETTE_ITEMS, DEVINETTE_MOTS_BANK } from '../../../data/devinettes-mots-composes';

const CHOICES_COUNT = 5;

function normalizeAnswer(s: string): string {
  return s
    .trim()
    .toLowerCase()
    .normalize('NFC')
    .replace(/['']/g, "'")
    .replace(/\s+/g, ' ')
    .replace(/\s*-\s*/g, '-');
}

function withoutLeadingArticle(expected: string): string {
  const t = normalizeAnswer(expected);
  if (t.startsWith("l'")) return t.slice(2).trim();
  if (t.startsWith('le ')) return t.slice(3).trim();
  if (t.startsWith('la ')) return t.slice(3).trim();
  return t;
}

function matchesExpected(picked: string, expected: string): boolean {
  const n = normalizeAnswer(picked);
  const e = normalizeAnswer(expected);
  if (n === e) return true;
  const stripped = withoutLeadingArticle(expected);
  if (n === normalizeAnswer(stripped)) return true;
  return false;
}

function shuffle<T>(arr: T[]): T[] {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

/** La bonne réponse + 4 autres mots tirés de la banque, ordre mélangé. */
function buildFiveChoices(correct: string, bank: string[]): string[] {
  const correctNorm = normalizeAnswer(correct);
  const distractors = bank.filter((w) => normalizeAnswer(w) !== correctNorm);
  const need = CHOICES_COUNT - 1;
  const shuffledD = shuffle(distractors);
  let four = shuffledD.slice(0, need);
  let d = 0;
  while (four.length < need && distractors.length > 0) {
    four.push(distractors[d % distractors.length]!);
    d += 1;
  }
  return shuffle([correct, ...four]);
}

/**
 * Devinettes : une devinette à la fois, choix parmi cinq mots (clic).
 * Les réponses peuvent être des mots composés ou des mots simples.
 */
export function DevinettesMotsComposes(): React.ReactElement {
  const total = DEVINETTE_ITEMS.length;

  const [currentIndex, setCurrentIndex] = useState(0);
  const [feedback, setFeedback] = useState<'idle' | 'ok' | 'err'>('idle');
  const [errDetail, setErrDetail] = useState<string | null>(null);
  const [finished, setFinished] = useState(false);
  /** Pour mélanger à nouveau les 5 propositions au même index (ex. après erreur). */
  const [choiceKey, setChoiceKey] = useState(0);

  const item = useMemo(
    () => (finished ? null : DEVINETTE_ITEMS[currentIndex] ?? null),
    [currentIndex, finished],
  );

  const fiveChoices = useMemo(() => {
    if (!item) return [];
    return buildFiveChoices(item.answer, DEVINETTE_MOTS_BANK);
  }, [item, choiceKey]);

  const resetRound = useCallback(() => {
    setCurrentIndex(0);
    setFeedback('idle');
    setErrDetail(null);
    setFinished(false);
    setChoiceKey((k) => k + 1);
  }, []);

  const goNext = useCallback(() => {
    if (currentIndex >= total - 1) {
      setFinished(true);
      setFeedback('idle');
      setErrDetail(null);
      return;
    }
    setCurrentIndex((i) => i + 1);
    setFeedback('idle');
    setErrDetail(null);
    setChoiceKey((k) => k + 1);
  }, [currentIndex, total]);

  const onPickWord = useCallback(
    (word: string) => {
      if (finished || !item || feedback === 'ok') return;
      if (matchesExpected(word, item.answer)) {
        setFeedback('ok');
        setErrDetail(null);
      } else {
        setFeedback('err');
        setErrDetail('Ce n’est pas le bon mot. Choisis-en un autre.');
      }
    },
    [finished, item, feedback],
  );

  const rowClass =
    feedback === 'ok' ? ' devinettes-row-ok' : feedback === 'err' ? ' devinettes-row-err' : '';

  return (
    <ExerciseWrapper title="Devinettes" backPath="/francais">
      <div className="devinettes-sheet">
        <header className="devinettes-head">
          <span className="devinettes-badge" aria-hidden>
            3
          </span>
          <p className="devinettes-instruction">
            {finished
              ? 'Tu as répondu à toutes les devinettes.'
              : 'Clique sur le bon mot parmi les cinq propositions (une devinette à la fois).'}
          </p>
        </header>

        {!finished && item ? (
          <>
            <p className="devinettes-progress" aria-live="polite">
              Devinette {currentIndex + 1} / {total}
            </p>
            <div className="devinettes-list devinettes-list-single" role="group" aria-label="Énoncé et choix">
              <div className={`devinettes-row${rowClass}`}>
                <p className="devinettes-riddle">{item.riddle}</p>
                <div className="devinettes-choices" role="group" aria-label="Cinq mots au choix">
                  {fiveChoices.map((w) => {
                    const isCorrectPick = feedback === 'ok' && matchesExpected(w, item.answer);
                    const disabled = feedback === 'ok' && !isCorrectPick;
                    return (
                      <button
                        key={w}
                        type="button"
                        className={
                          'devinettes-choice' +
                          (isCorrectPick ? ' devinettes-choice-correct' : '') +
                          (disabled ? ' devinettes-choice-disabled' : '')
                        }
                        onClick={() => onPickWord(w)}
                        disabled={disabled}
                        aria-pressed={isCorrectPick}
                      >
                        {w}
                      </button>
                    );
                  })}
                </div>
              </div>
            </div>
          </>
        ) : null}

        {finished ? (
          <p className="devinettes-success devinettes-finished-msg" role="status">
            Bravo ! Tu as terminé les {total} devinettes.
          </p>
        ) : null}

        <footer className="devinettes-footer">
          {!finished && feedback === 'ok' ? (
            <p className="devinettes-success" role="status">
              Bravo ! Bonne réponse.
            </p>
          ) : null}
          {!finished && feedback === 'err' && errDetail ? (
            <p className="devinettes-error" role="alert">
              {errDetail}
            </p>
          ) : null}
          <div className="devinettes-actions">
            {!finished && feedback === 'ok' ? (
              <button type="button" className="devinettes-btn devinettes-btn-primary" onClick={goNext}>
                {currentIndex >= total - 1 ? 'Terminer' : 'Question suivante'}
              </button>
            ) : null}
            <button type="button" className="devinettes-btn" onClick={resetRound}>
              Recommencer
            </button>
          </div>
        </footer>
      </div>
    </ExerciseWrapper>
  );
}
