import React, { createContext, useContext, useState, useCallback, ReactNode } from 'react';

/** Type du contexte de score partagé dans toute l'application */
interface ScoreContextType {
  score: number;
  /** Ajoute 1 point (bonne réponse) */
  addPoint: () => void;
  /** Retire 1 point, minimum 0 (mauvaise réponse) */
  removePoint: () => void;
}

/** Contexte global du score — initialisé avec des valeurs par défaut */
const ScoreContext = createContext<ScoreContextType>({
  score: 0,
  addPoint: () => {},
  removePoint: () => {},
});

/**
 * Provider du score à placer au niveau de App.tsx.
 * Le score persiste entre les exercices mais repart à 0 au refresh de la page.
 */
export function ScoreProvider({ children }: { children: ReactNode }): React.ReactElement {
  const [score, setScore] = useState(0);

  const addPoint = useCallback(() => setScore((s) => s + 1), []);
  const removePoint = useCallback(() => setScore((s) => Math.max(0, s - 1)), []);

  return (
    <ScoreContext.Provider value={{ score, addPoint, removePoint }}>
      {children}
    </ScoreContext.Provider>
  );
}

/** Hook pour accéder au score global depuis n'importe quel composant */
export function useScore(): ScoreContextType {
  return useContext(ScoreContext);
}
