import React from 'react';
import { SubjectList } from '../../components/SubjectList';
import { filterSciencesExercisesForGrade } from '../../data/navFilter';
import { useSchoolYear } from '../../hooks/useSchoolYear';

/** Page Sciences : nutrition, temps, électricité */
export function SciencesHome(): React.ReactElement {
  const { grade } = useSchoolYear();
  const items = filterSciencesExercisesForGrade(grade);
  return <SubjectList title="Sciences" items={items} backPath="/" />;
}
