import { useState, useCallback } from 'react';
import { randomInRange } from '../../../../utils/randomInRange';
import { useScore } from '../../../../hooks/useScore';
import { PROBLEM_TEMPLATES, ProblemTemplate } from '../../../../data/problemes';

/** Données d'un problème généré */
interface ProblemData {
  text: string;
  a: number;
  b: number;
  answer: number;
  operation: '+' | '-';
}

/** Champ de l'équation en cours d'édition */
export type EquationField = 'a' | 'b' | 'result';

interface UseProblemeReturn {
  problem: ProblemData;
  /** Champ actuellement sélectionné pour la saisie */
  selectedField: EquationField;
  setSelectedField: (f: EquationField) => void;
  /** Valeurs saisies par l'enfant */
  values: Record<EquationField, string>;
  /** Opérateur choisi par l'enfant (null = pas encore choisi) */
  selectedOperator: '+' | '-' | null;
  toggleOperator: () => void;
  /** Valeur du champ sélectionné (pour le NumPad) */
  currentValue: string;
  setCurrentValue: (v: string) => void;
  /** Passe au champ suivant vide, ou valide si tout est rempli */
  advanceOrCheck: () => void;
  isCorrect: boolean | null;
  next: () => void;
  range: { min: number; max: number };
  updateRange: (r: { min: number; max: number }) => void;
}

/** Génère un problème à partir d'un template aléatoire */
function generateProblem(min: number, max: number): ProblemData {
  const template: ProblemTemplate =
    PROBLEM_TEMPLATES[randomInRange(0, PROBLEM_TEMPLATES.length - 1)];

  let a: number, b: number, answer: number;
  if (template.operation === '+') {
    a = randomInRange(min, Math.floor(max / 2));
    b = randomInRange(min, Math.floor(max / 2));
    answer = a + b;
  } else {
    a = randomInRange(min + 1, max);
    b = randomInRange(min, a - 1);
    answer = a - b;
  }

  const text = template.text.replace('{a}', String(a)).replace('{b}', String(b));
  return { text, a, b, answer, operation: template.operation };
}

/**
 * Hook pour l'exercice de problèmes (version équation).
 * L'enfant doit traduire le problème en calcul : choisir +/- et remplir a, b, résultat.
 */
export function useProbleme(): UseProblemeReturn {
  const { addPoint, removePoint } = useScore();
  const [range, setRange] = useState({ min: 1, max: 30 });
  const [problem, setProblem] = useState(() => generateProblem(1, 30));
  const [selectedField, setSelectedField] = useState<EquationField>('a');
  const [values, setValues] = useState<Record<EquationField, string>>({ a: '', b: '', result: '' });
  const [selectedOperator, setSelectedOperator] = useState<'+' | '-' | null>(null);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);

  /** Valeur du champ actuellement sélectionné */
  const currentValue = values[selectedField];

  /** Met à jour la valeur du champ sélectionné */
  const setCurrentValue = useCallback(
    (v: string) => setValues((prev) => ({ ...prev, [selectedField]: v })),
    [selectedField]
  );

  /** Bascule l'opérateur entre + et - */
  const toggleOperator = useCallback(() => {
    setSelectedOperator((prev) => (prev === '+' ? '-' : '+'));
  }, []);

  /** Vérifie si l'équation complète est correcte */
  const checkEquation = useCallback(() => {
    const a = parseInt(values.a, 10);
    const b = parseInt(values.b, 10);
    const result = parseInt(values.result, 10);
    if (isNaN(a) || isNaN(b) || isNaN(result) || !selectedOperator) return;

    let correct = false;
    if (selectedOperator === problem.operation) {
      if (problem.operation === '+') {
        /* Addition : accepte a et b dans n'importe quel ordre */
        const expected = [problem.a, problem.b].sort((x, y) => x - y);
        const user = [a, b].sort((x, y) => x - y);
        correct = expected[0] === user[0] && expected[1] === user[1] && result === problem.answer;
      } else {
        correct = a === problem.a && b === problem.b && result === problem.answer;
      }
    }

    setIsCorrect(correct);
    if (correct) addPoint();
    else removePoint();
  }, [values, selectedOperator, problem, addPoint, removePoint]);

  /** Avance au prochain champ vide ou valide si tout est rempli */
  const advanceOrCheck = useCallback(() => {
    const fields: EquationField[] = ['a', 'b', 'result'];
    const nextEmpty = fields.find((f) => !values[f] && f !== selectedField);

    if (nextEmpty) {
      setSelectedField(nextEmpty);
    } else if (values.a && values.b && values.result && selectedOperator) {
      checkEquation();
    }
  }, [values, selectedField, selectedOperator, checkEquation]);

  const next = useCallback(() => {
    setProblem(generateProblem(range.min, range.max));
    setValues({ a: '', b: '', result: '' });
    setSelectedOperator(null);
    setSelectedField('a');
    setIsCorrect(null);
  }, [range]);

  const updateRange = useCallback((r: { min: number; max: number }) => {
    setRange(r);
    setProblem(generateProblem(r.min, r.max));
    setValues({ a: '', b: '', result: '' });
    setSelectedOperator(null);
    setSelectedField('a');
    setIsCorrect(null);
  }, []);

  return {
    problem, selectedField, setSelectedField, values,
    selectedOperator, toggleOperator, currentValue, setCurrentValue,
    advanceOrCheck, isCorrect, next, range, updateRange,
  };
}
