import React, { useCallback, useState } from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import {
  generateCoccinelleExercise,
  type CoccinelleGrilleExercise,
} from '../../../data/coccinelles-grilles';

function cellKey(row: number, col: number): string {
  return `${row},${col}`;
}

function CoccinelleGrid({
  exercise,
  selected,
  disabled,
  showResult,
  ok,
  onSelect,
}: {
  exercise: CoccinelleGrilleExercise;
  selected: { row: number; col: number } | null;
  disabled: boolean;
  showResult: boolean;
  ok: boolean | null;
  onSelect: (row: number, col: number) => void;
}): React.ReactElement {
  const { rows, cols, startRow, startCol, arrivalColor, endRow, endCol } = exercise;

  const arrivalClass =
    arrivalColor === 'red'
      ? 'cocc-cell-arrival-red'
      : arrivalColor === 'green'
        ? 'cocc-cell-arrival-green'
        : 'cocc-cell-arrival-yellow';

  return (
    <div
      className="cocc-grid"
      style={{ gridTemplateRows: `repeat(${rows}, 1fr)`, gridTemplateColumns: `repeat(${cols}, 1fr)` }}
      role="grid"
      aria-label={`Quadrillage ${rows} par ${cols}`}
    >
      {Array.from({ length: rows * cols }, (_, i) => {
        const row = Math.floor(i / cols);
        const col = i % cols;
        const isStart = row === startRow && col === startCol;
        const isSelected = selected !== null && selected.row === row && selected.col === col;
        const isExpected = row === endRow && col === endCol;
        const showWrong = showResult && !ok && isSelected && !isExpected;
        const showRight = showResult && isSelected && ok;
        const showHint = showResult && !ok && isExpected;

        let cls = 'cocc-cell';
        if (isStart) cls += ' cocc-cell-start';
        if (isSelected && !disabled) cls += ` ${arrivalClass}`;
        if (showWrong) cls += ' cocc-cell-wrong';
        if (showRight) cls += ' cocc-cell-right';
        if (showHint) cls += ' cocc-cell-hint';

        return (
          <button
            key={cellKey(row, col)}
            type="button"
            className={cls}
            disabled={disabled}
            onClick={() => onSelect(row, col)}
            aria-label={
              isStart
                ? `Case départ, coccinelle (ligne ${row + 1}, colonne ${col + 1})`
                : `Case ligne ${row + 1}, colonne ${col + 1}`
            }
            aria-pressed={isSelected && !isStart}
          >
            {isStart ? <span className="cocc-ladybug" aria-hidden>🐞</span> : null}
          </button>
        );
      })}
    </div>
  );
}

function levelMeta(level: 1 | 2 | 3): string {
  if (level === 1) return 'Grille 3×3 · 2 déplacements';
  return `Grille 4×4 · ${level === 2 ? 3 : 4} déplacements`;
}

/**
 * « Vite ! » — un quadrillage à la fois, niveaux progressifs, parcours aléatoires.
 */
export function CoccinellesGrilles(): React.ReactElement {
  const [level, setLevel] = useState<1 | 2 | 3>(1);
  const [failStreak, setFailStreak] = useState(0);
  const [roundKey, setRoundKey] = useState(0);
  const [exercise, setExercise] = useState<CoccinelleGrilleExercise>(() =>
    generateCoccinelleExercise(1, Math.random)
  );

  const [phase, setPhase] = useState<'playing' | 'feedback'>('playing');
  const [selected, setSelected] = useState<{ row: number; col: number } | null>(null);
  const [lastOk, setLastOk] = useState<boolean | null>(null);
  const [feedbackMsg, setFeedbackMsg] = useState<string>('');

  const spawnExercise = useCallback((lv: 1 | 2 | 3) => {
    setExercise(generateCoccinelleExercise(lv, Math.random));
    setRoundKey((k) => k + 1);
    setSelected(null);
    setPhase('playing');
    setLastOk(null);
    setFeedbackMsg('');
  }, []);

  const setPick = (row: number, col: number) => {
    if (phase !== 'playing') return;
    setSelected((cur) => {
      if (cur !== null && cur.row === row && cur.col === col) return null;
      return { row, col };
    });
  };

  const verify = useCallback(() => {
    if (!selected || phase !== 'playing') return;
    const ok = selected.row === exercise.endRow && selected.col === exercise.endCol;
    setLastOk(ok);

    if (ok) {
      const nextLevel = Math.min(3, level + 1) as 1 | 2 | 3;
      setFailStreak(0);
      setLevel(nextLevel);
      if (level < 3) {
        setFeedbackMsg(`Bravo ! Tu passes au niveau ${nextLevel}.`);
      } else {
        setFeedbackMsg('Bravo ! Nouvelle grille au niveau 3.');
      }
    } else if (failStreak >= 1) {
      const nextLevel = Math.max(1, level - 1) as 1 | 2 | 3;
      const dropped = nextLevel < level;
      setLevel(nextLevel);
      setFailStreak(0);
      setFeedbackMsg(
        dropped
          ? "Pas tout à fait. On revient d'un niveau pour s'entraîner encore."
          : "Pas tout à fait. Tu es déjà au niveau 1 : voici une autre grille."
      );
    } else {
      setFailStreak(1);
      setFeedbackMsg('Pas tout à fait. Réessaie : même niveau, autre grille.');
    }

    setPhase('feedback');
  }, [selected, phase, exercise.endRow, exercise.endCol, level, failStreak]);

  const continuer = useCallback(() => {
    spawnExercise(level);
  }, [level, spawnExercise]);

  const toutRecommencer = useCallback(() => {
    setLevel(1);
    setFailStreak(0);
    spawnExercise(1);
  }, [spawnExercise]);

  const showResult = phase === 'feedback' && lastOk !== null;
  const ok = lastOk;

  return (
    <ExerciseWrapper title="Vite !" backPath="/maths">
      <div className="cocc-page">
        <p className="cocc-directions">
          VERS LE HAUT — VERS LE BAS — VERS LA GAUCHE — VERS LA DROITE
        </p>
        <p className="cocc-intro">
          Un exercice à la fois : lis les déplacements, puis clique sur la case d&apos;arrivée (reclique pour
          effacer). La grille change à chaque fois.
        </p>

        <section
          className="cocc-ex-block"
          style={{ borderColor: exercise.frameColor }}
          aria-labelledby="cocc-titre-actif"
        >
          <div className="cocc-ex-head">
            <span className="cocc-ex-badge" style={{ background: exercise.frameColor }}>
              {level}
            </span>
            <div>
              <h2 id="cocc-titre-actif" className="cocc-ex-title">
                Niveau {level}
              </h2>
              <p className="cocc-level-meta">{levelMeta(level)}</p>
            </div>
          </div>
          <div className="cocc-ex-body">
            <p className="cocc-ex-text">{exercise.instruction}</p>
            <CoccinelleGrid
              key={roundKey}
              exercise={exercise}
              selected={selected}
              disabled={phase === 'feedback'}
              showResult={showResult}
              ok={ok}
              onSelect={setPick}
            />
          </div>
        </section>

        <footer className="cocc-footer">
          {phase === 'feedback' && feedbackMsg ? (
            <p className={`cocc-summary ${lastOk ? 'cocc-summary-ok' : 'cocc-summary-err'}`} role="status">
              {feedbackMsg}
            </p>
          ) : null}
          <div className="cocc-actions">
            {phase === 'playing' ? (
              <button
                type="button"
                className="cocc-btn cocc-btn-primary"
                disabled={selected === null}
                onClick={verify}
              >
                Vérifier
              </button>
            ) : (
              <button type="button" className="cocc-btn cocc-btn-primary" onClick={continuer}>
                Exercice suivant
              </button>
            )}
            <button type="button" className="cocc-btn" onClick={toutRecommencer}>
              Tout recommencer
            </button>
          </div>
        </footer>
      </div>
    </ExerciseWrapper>
  );
}
