import React from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { Feedback } from '../../../components/Feedback';
import { useExerciseAnswerLimit } from '../../../hooks/useExerciseAnswerLimit';
import { useDizaines } from './useDizaines';

const BACK_PATH = '/maths';

function digitsOnly(value: string, maxLen: number): string {
  return value.replace(/\D/g, '').slice(0, maxLen);
}

/**
 * Écris la dizaine inférieure et la dizaine supérieure (nombres 1–99, jamais 10, 20, …).
 * Champs texte (pas type number) pour éviter les flèches +/- du navigateur.
 */
export function DizainesEncadrement(): React.ReactElement {
  const {
    n,
    lowerInput,
    upperInput,
    setLowerInput,
    setUpperInput,
    isCorrect,
    check,
    next,
    lowerExpected,
    upperExpected,
  } = useDizaines();
  const { wrapNext } = useExerciseAnswerLimit(BACK_PATH);

  return (
    <ExerciseWrapper title="Dizaines" backPath={BACK_PATH}>
      <p style={{ fontSize: 16, color: '#7F8C8D', textAlign: 'center', marginBottom: 8 }}>
        Écris la dizaine en dessous et la dizaine au-dessus.
      </p>

      <div className="dizaines-target">{n}</div>

      {isCorrect === null ? (
        <>
          <div
            className="dizaines-inputs"
            role="group"
            aria-label="Dizaine en dessous et dizaine au-dessus"
          >
            <label htmlFor="dizaines-lower" className="dizaines-label dizaines-grid-label-lower">
              En dessous
            </label>
            <span className="dizaines-sep dizaines-grid-sep" aria-hidden>
              et
            </span>
            <label htmlFor="dizaines-upper" className="dizaines-label dizaines-grid-label-upper">
              Au-dessus
            </label>
            <input
              id="dizaines-lower"
              type="text"
              inputMode="numeric"
              autoComplete="off"
              className="dizaines-input dizaines-grid-input-lower"
              value={lowerInput}
              onChange={(e) => setLowerInput(digitsOnly(e.target.value, 3))}
              placeholder="?"
              aria-label="Dizaine inférieure"
            />
            <input
              id="dizaines-upper"
              type="text"
              inputMode="numeric"
              autoComplete="off"
              className="dizaines-input dizaines-grid-input-upper"
              value={upperInput}
              onChange={(e) => setUpperInput(digitsOnly(e.target.value, 3))}
              placeholder="?"
              aria-label="Dizaine supérieure"
            />
          </div>
          <button type="button" className="feedback-next" onClick={check}>
            Vérifier
          </button>
        </>
      ) : (
        <Feedback
          isCorrect={isCorrect}
          detail={
            isCorrect
              ? undefined
              : `C’était ${lowerExpected} et ${upperExpected}`
          }
          onNext={() => wrapNext(next)}
        />
      )}
    </ExerciseWrapper>
  );
}
