import React, { useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useSchoolYear } from '../hooks/useSchoolYear';
import { getGradesForPathname } from '../data/navFilter';

/**
 * Redirige vers l'accueil si l'exercice courant n'est pas prévu pour la classe choisie.
 */
export function GradeRouteSync(): React.ReactElement | null {
  const { pathname } = useLocation();
  const { grade } = useSchoolYear();
  const navigate = useNavigate();

  useEffect(() => {
    const allowed = getGradesForPathname(pathname);
    if (allowed === null) return;
    if (!allowed.includes(grade)) {
      navigate('/', { replace: true });
    }
  }, [pathname, grade, navigate]);

  return null;
}
